def generate_id() -> str:
    """Generate unique ID - full UUID for database"""
    return str(uuid.uuid4())


def next_doc_number(records: list, field: str, prefix: str, pad: int = 5) -> str:
    """Generate next document number by finding max existing number.
    
    Args:
        records: List of existing records
        field: Field name containing the number (e.g. 'po_number', 'grv_number')
        prefix: Prefix to strip (e.g. 'PO-', 'GRV-', 'INV')
        pad: Zero-padding width (default 5)
    
    Returns: Next number string like 'PO-00042'
    """
    max_num = 0
    for r in records:
        val = str(r.get(field, ""))
        try:
            # Strip the prefix and any extra dashes
            num_str = val.replace(prefix, "").lstrip("-").lstrip("0") or "0"
            num = int(num_str)
            if num > max_num:
                max_num = num
        except (ValueError, TypeError):
            pass
    return f"{prefix}{max_num + 1:0{pad}d}"


def smart_stock_code(description: str, existing_codes: set = None) -> str:
    """Generate a smart, unique stock code from a product description.
    
    Examples:
        'BOLT M10X110 HT'           → BLT-10-110-HT
        'SAFETY BOOT DOT STC CHELSEA BROWN 9' → SFT-BT-CHEL-9
        'GUMBOOT SHOVA WHITE/GREY 9' → GMB-SHOV-9
        'CL ANKLE NSTC OUTBACK BLACK 8' → ANK-OUTB-BLK-8
        'HOSE CLAMP GS36 44X70MM'   → HS-CL-GS36-44X70
        'SILICONE CLEAR 260ML'      → SIL-CLR-260
        'FLAT BAR 40X3 SS'          → FL-BR-40X3-SS
    """
    import re
    if not description:
        return "ITM-001"
    
    if existing_codes is None:
        existing_codes = set()
    
    desc = description.upper().strip()
    words = desc.split()
    
    # Product type codes - PRIMARY identifier
    product_types = {
        "BOLT": "BLT", "BOLTS": "BLT", "NUT": "NT", "NUTS": "NT",
        "WASHER": "WS", "WASHERS": "WS", "SCREW": "SCR", "SCREWS": "SCR",
        "STUD": "STD", "RIVET": "RVT", "BEARING": "BRG", "CIRCLIP": "CLP",
        "SEAL": "SL", "ORING": "OR", "SET": "SET", "CAP": "CAP",
        "PIPE": "PP", "TUBE": "TB", "BAR": "BR", "ANGLE": "AN",
        "CHANNEL": "CHL", "BEAM": "BM", "SHEET": "SH", "PLATE": "PL",
        "ELBOW": "EL", "TEE": "TE", "VALVE": "VL", "FLANGE": "FLG",
        "REDUCER": "RED", "COUPLING": "CPL", "NIPPLE": "NIP", "PLUG": "PLG",
        "BUSH": "BSH", "FITTING": "FIT", "CLAMP": "CL", "HOSE": "HS",
        "CABLE": "CB", "CHAIN": "CH", "DISC": "DSC", "SANDPAPER": "SND",
        "SILICONE": "SIL", "ADHESIVE": "ADH", "TAPE": "TP",
    }
    
    # Footwear/PPE - need EXTRA detail (brand/style) because many variants per size
    footwear_types = {
        "BOOT": "BT", "BOOTS": "BT", "SHOE": "SH", "SHOES": "SH",
        "GUMBOOT": "GMB", "GUMBOOTS": "GMB",
        "SAFETY": "SFT", "ANKLE": "ANK", "OVERALL": "OVL", "OVERALLS": "OVL",
        "JACKET": "JKT", "GLOVE": "GL", "GLOVES": "GL",
        "CONTI": "CNT", "GOGGLE": "GGL", "GOGGLES": "GGL",
        "HELMET": "HLM", "HARDHAT": "HH", "VEST": "VST",
        "EARPLUG": "EP", "EARMUFF": "EM", "MASK": "MSK", "RESPIRATOR": "RSP",
    }
    
    # Modifiers that should appear in code
    modifier_map = {
        "HT": "HT", "Z/P": "ZP", "S/S": "SS", "SS": "SS",
        "GALV": "GV", "GALVANISED": "GV", "GALVANIZED": "GV",
        "BLACK": "BLK", "WHITE": "WHT", "GREY": "GRY", "GRAY": "GRY",
        "BROWN": "BRN", "RED": "RED", "BLUE": "BLU", "GREEN": "GRN",
        "YELLOW": "YEL", "ORANGE": "ORG", "CLEAR": "CLR",
        "CHROME": "CHR", "BRASS": "BRS", "COPPER": "CU", "NYLON": "NYL",
        "PVC": "PVC", "HDPE": "HDPE", "MILD": "MS",
    }
    
    # Colour words to skip when building brand/style parts
    colours = {"BLACK", "WHITE", "GREY", "GRAY", "BROWN", "RED", "BLUE", "GREEN", 
               "YELLOW", "ORANGE", "CLEAR", "CHROME"}
    
    # Skip words (noise)
    skip_words = {"THE", "AND", "FOR", "WITH", "IN", "OF", "A", "AN", "PER", 
                  "EACH", "PAIR", "SIZE", "NO", "NR", "NUMBER", "PACK",
                  "STC", "NSTC", "DOT", "SABS", "CL"}
    
    # Extract sizes and dimensions
    sizes = re.findall(r'(\d+(?:\.\d+)?)\s*[Xx]\s*(\d+(?:\.\d+)?)', desc)
    plain_sizes = re.findall(r'(?<![Xx/\d])(\d+(?:\.\d+)?)(?:MM|ML|M|CM|KG|L)?(?![Xx/\d])', desc)
    
    # Find product type
    product_code = ""
    is_footwear = False
    for w in words:
        w_clean = w.strip(".,;:-/()")
        if w_clean in footwear_types:
            product_code = footwear_types[w_clean]
            is_footwear = True
            break
        if w_clean in product_types:
            product_code = product_types[w_clean]
            break
    
    # For footwear, check if compound like "SAFETY BOOT" or "GUMBOOT"
    if is_footwear:
        # Build code: TYPE + BRAND/STYLE + SIZE
        parts = []
        
        # Check for compound types: "SAFETY BOOT" → SFT-BT
        compound_types = [
            (["SAFETY", "BOOT"], "SFT-BT"), (["SAFETY", "BOOTS"], "SFT-BT"),
            (["SAFETY", "SHOE"], "SFT-SH"), (["SAFETY", "SHOES"], "SFT-SH"),
            (["ANKLE", "BOOT"], "ANK-BT"), (["ANKLE", "BOOTS"], "ANK-BT"),
        ]
        compound_found = False
        for comp_words, comp_code in compound_types:
            if all(cw in words or any(cw in w for w in words) for cw in comp_words):
                parts.append(comp_code)
                compound_found = True
                break
        
        if not compound_found:
            parts.append(product_code)
        
        # Add brand/style words (CHELSEA, SHOVA, INKUNZI, OUTBACK, UTECH etc)
        type_words = set(k for k in {**footwear_types, **product_types})
        brand_parts = []
        for w in words:
            w_clean = w.strip(".,;:-/()")
            if (w_clean not in type_words and w_clean not in skip_words and 
                w_clean not in colours and len(w_clean) > 1 and 
                w_clean.isalpha() and not w_clean.isdigit()):
                brand_parts.append(w_clean[:4])
                if len(brand_parts) >= 2:
                    break
        if brand_parts:
            parts.extend(brand_parts[:2])
        
        # Add colour if present
        for w in words:
            w_clean = w.strip(".,;:-/()")
            if w_clean in modifier_map and w_clean in colours:
                parts.append(modifier_map[w_clean])
                break
        
        # Add size (last plain number is usually shoe size)
        if plain_sizes:
            parts.append(plain_sizes[-1])
        
        smart_code = "-".join(parts)
    
    elif product_code:
        # Regular products: TYPE + DIMENSIONS + MODIFIERS
        parts = [product_code]
        
        # Add dimension sizes (e.g. M10X110, 40X3)
        if sizes:
            for dim in sizes[:2]:
                parts.append(f"{dim[0]}X{dim[1]}")
        elif plain_sizes:
            for s in plain_sizes[:2]:
                parts.append(s)
        
        # Check for product sub-codes (GS36, M10, etc) - but NOT parts of dimensions
        sub_codes = re.findall(r'([A-Z]{1,3}\d{1,4})', desc)
        dim_numbers = set()
        for dim in sizes:
            dim_numbers.add(dim[0])
            dim_numbers.add(dim[1])
        for sc in sub_codes:
            sc_num = re.sub(r'[A-Z]', '', sc)
            if sc not in parts and len(sc) <= 5 and sc_num not in dim_numbers:
                parts.insert(1, sc)
                break
        
        # Add modifiers (HT, ZP, SS etc)
        for w in words:
            w_clean = w.strip(".,;:-/()")
            if w_clean in modifier_map and modifier_map[w_clean] not in parts:
                parts.append(modifier_map[w_clean])
        
        smart_code = "-".join(parts)
    
    else:
        # Unknown product type - use first significant words + sizes
        parts = []
        for w in words:
            w_clean = w.strip(".,;:-/()")
            if w_clean in modifier_map:
                parts.append(modifier_map[w_clean])
            elif w_clean not in skip_words and len(w_clean) > 1 and w_clean.isalpha():
                parts.append(w_clean[:3])
            if len(parts) >= 3:
                break
        if plain_sizes:
            parts.append(plain_sizes[0])
        smart_code = "-".join(parts) if parts else desc[:8].replace(" ", "-")
    
    # Trim to max length
    smart_code = smart_code[:20].upper().rstrip("-")
    
    # Ensure uniqueness
    final_code = smart_code
    counter = 1
    while final_code.upper() in {c.upper() for c in existing_codes}:
        final_code = f"{smart_code}-{counter}"
        counter += 1
    
    return final_code

def is_valid_uuid(value) -> bool:
    """Check if a value is a valid UUID format"""
    if not value:
        return False
    import re
    uuid_pattern = re.compile(r'^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$', re.I)
    return bool(uuid_pattern.match(str(value)))

def safe_uuid(value):
    """Return UUID if valid, else None (for database UUID columns)"""
    return value if is_valid_uuid(value) else None

def now() -> str:
    """Current timestamp in ISO 8601 format for Supabase - always UTC"""
    return datetime.utcnow().isoformat() + 'Z'

def today() -> str:
    """Current date in SA timezone (UTC+2)"""
    sa_time = datetime.utcnow() + timedelta(hours=2)
    return sa_time.strftime("%Y-%m-%d")

def money(amount) -> str:
    """Format as currency"""
    try:
        return f"R{float(amount):,.2f}"
    except:
        return "R0.00"


def calc_customer_balance(biz_id: str, customer_id: str) -> float:
    """Calculate customer balance from source documents (invoices, credit notes, receipts, account sales).
    Positive = customer owes us.  Negative = customer in credit (overpaid).
    Balance = invoices + account_sales - receipts - credit_notes
    """
    try:
        # Debits: what customer owes
        invoices = db.get("invoices", {"business_id": biz_id, "customer_id": customer_id}) or []
        inv_total = sum(float(i.get("total", 0)) for i in invoices if i.get("status") != "credited")

        # Account sales (POS on-account)
        sales = db.get("sales", {"business_id": biz_id, "customer_id": customer_id}) or []
        acc_sales_total = sum(float(s.get("total", 0)) for s in sales if s.get("payment_method") == "account")

        # Credits: what customer has paid / been credited
        receipts_by_id = db.get("receipts", {"business_id": biz_id, "customer_id": customer_id}) or []
        # Also pick up unlinked receipts matched by name (from banking recon)
        all_receipts = db.get("receipts", {"business_id": biz_id}) or []
        _cust = db.get_one("customers", customer_id)
        _cust_name_upper = (_cust.get("name") or "").upper().strip() if _cust else ""
        _by_id_set = {r.get("id") for r in receipts_by_id}
        receipts_by_name = [r for r in all_receipts
                            if not r.get("customer_id") and _cust_name_upper
                            and (r.get("customer_name") or "").upper().strip() == _cust_name_upper
                            and r.get("id") not in _by_id_set]
        all_cust_receipts = receipts_by_id + receipts_by_name
        rec_total = sum(float(r.get("amount", 0)) for r in all_cust_receipts)

        credit_notes = db.get("credit_notes", {"business_id": biz_id, "customer_id": customer_id}) or []
        # Exclude credit notes whose linked invoice is fully credited (both cancel out)
        _credited_inv_nums = {i.get("invoice_number") for i in invoices if i.get("status") == "credited"}
        cn_total = sum(float(cn.get("total", 0)) for cn in credit_notes
                       if cn.get("invoice_number", "") not in _credited_inv_nums)

        return round(inv_total + acc_sales_total - rec_total - cn_total, 2)
    except Exception as e:
        logger.error(f"[CALC BALANCE] Customer {customer_id} error: {e}")
        return 0.0


def calc_supplier_balance(biz_id: str, supplier_id: str) -> float:
    """Calculate supplier balance from source documents (supplier invoices, expenses, payments).
    Positive = we owe the supplier.  Negative = we overpaid / supplier in credit.
    Balance = supplier_invoices - supplier_payments
    """
    try:
        # What we owe: supplier invoices
        s_invoices = db.get("supplier_invoices", {"business_id": biz_id, "supplier_id": supplier_id}) or []
        si_total = sum(float(si.get("total", 0)) for si in s_invoices if si.get("status") != "cancelled")

        # What we paid
        all_payments = db.get("supplier_payments", {"business_id": biz_id}) or []
        _sup = db.get_one("suppliers", supplier_id)
        _sup_name_upper = (_sup.get("name") or "").upper().strip() if _sup else ""
        payments = [p for p in all_payments if
                    p.get("supplier_id") == supplier_id or
                    (not p.get("supplier_id") and _sup_name_upper and
                     (p.get("supplier_name") or "").upper().strip() == _sup_name_upper)]
        pay_total = sum(float(p.get("amount", 0)) for p in payments)

        return round(si_total - pay_total, 2)
    except Exception as e:
        logger.error(f"[CALC BALANCE] Supplier {supplier_id} error: {e}")
        return 0.0


def calc_all_customer_balances(biz_id: str) -> dict:
    """Calculate balances for ALL customers in one batch. Returns {customer_id: balance}.
    Much more efficient than calling calc_customer_balance() per customer.
    """
    try:
        all_invoices = db.get("invoices", {"business_id": biz_id}) or []
        all_sales = db.get("sales", {"business_id": biz_id}) or []
        all_receipts = db.get("receipts", {"business_id": biz_id}) or []
        all_credit_notes = db.get("credit_notes", {"business_id": biz_id}) or []
        all_customers = db.get("customers", {"business_id": biz_id}) or []

        # Build name→id map for unlinked receipt matching
        _name_to_id = {}
        for c in all_customers:
            _n = (c.get("name") or "").upper().strip()
            if _n:
                _name_to_id[_n] = c.get("id", "")

        balances = {}

        # Debits: invoices (excluding credited)
        for inv in all_invoices:
            cid = inv.get("customer_id", "")
            if cid and inv.get("status") != "credited":
                balances[cid] = balances.get(cid, 0) + float(inv.get("total", 0))

        # Debits: account sales
        for s in all_sales:
            if s.get("payment_method") == "account":
                cid = s.get("customer_id", "")
                if cid:
                    balances[cid] = balances.get(cid, 0) + float(s.get("total", 0))

        # Credits: receipts
        for r in all_receipts:
            cid = r.get("customer_id", "")
            if not cid:
                # Try name match
                _rname = (r.get("customer_name") or "").upper().strip()
                cid = _name_to_id.get(_rname, "")
            if cid:
                balances[cid] = balances.get(cid, 0) - float(r.get("amount", 0))

        # Credits: credit notes
        for cn in all_credit_notes:
            cid = cn.get("customer_id", "")
            if cid:
                balances[cid] = balances.get(cid, 0) - float(cn.get("total", 0))

        return {k: round(v, 2) for k, v in balances.items()}
    except Exception as e:
        logger.error(f"[CALC BATCH] Customer balances error: {e}")
        return {}


def calc_all_supplier_balances(biz_id: str) -> dict:
    """Calculate balances for ALL suppliers in one batch. Returns {supplier_id: balance}.
    Much more efficient than calling calc_supplier_balance() per supplier.
    """
    try:
        all_s_invoices = db.get("supplier_invoices", {"business_id": biz_id}) or []
        all_s_payments = db.get("supplier_payments", {"business_id": biz_id}) or []
        all_suppliers = db.get("suppliers", {"business_id": biz_id}) or []

        # Build name→id map for unlinked payment matching
        _name_to_id = {}
        for s in all_suppliers:
            _n = (s.get("name") or "").upper().strip()
            if _n:
                _name_to_id[_n] = s.get("id", "")

        balances = {}

        # Debits: supplier invoices (what we owe)
        for si in all_s_invoices:
            sid = si.get("supplier_id", "")
            if sid and si.get("status") != "cancelled":
                balances[sid] = balances.get(sid, 0) + float(si.get("total", 0))

        # Credits: supplier payments
        for p in all_s_payments:
            sid = p.get("supplier_id", "")
            if not sid:
                _pname = (p.get("supplier_name") or "").upper().strip()
                sid = _name_to_id.get(_pname, "")
            if sid:
                balances[sid] = balances.get(sid, 0) - float(p.get("amount", 0))

        return {k: round(v, 2) for k, v in balances.items()}
    except Exception as e:
        logger.error(f"[CALC BATCH] Supplier balances error: {e}")
        return {}


def get_acting_user() -> tuple:
    """Get the logged-in user's ID and display name — auto-fills created_by everywhere.
    Returns (user_id, user_name) — always strings, never None.
    """
    user = Auth.get_current_user()
    if not user:
        return "", "System"
    uid = user.get("id", "")
    name = user.get("name") or user.get("email") or "Unknown"
    return uid, name


def next_document_number(prefix: str, existing_docs: list, field: str = "invoice_number") -> str:
    """Generate next sequential document number, safe even after deletions.
    Extracts max number from existing docs and adds 1.
    prefix: 'INV-', 'QU-', 'CN-', 'DN-', 'PO-' etc.
    """
    import re
    max_num = 0
    for doc in existing_docs:
        num_str = doc.get(field, "")
        if isinstance(num_str, str):
            # Extract digits after prefix
            match = re.search(r'(\d+)', num_str.replace(prefix, ""))
            if match:
                num = int(match.group(1))
                if num > max_num:
                    max_num = num
    return f"{prefix}{max_num + 1:05d}"

def extract_time(timestamp_str) -> str:
    """Extract HH:MM from any timestamp format, converted to SA time (UTC+2)
    Handles: 2026-02-16T18:57:32+00:00, 2026-02-16T18:57:32.123456+00:00, 
             2026-02-16T18:57:32Z, 2026-02-16T18:57:32.388Z
    """
    try:
        ts = str(timestamp_str or "")
        if 'T' in ts:
            time_part = ts.split('T')[1]
            hh = int(time_part[:2])
            mm = time_part[3:5]
            # If timestamp is UTC (ends with Z or +00:00), add 2 hours for SA
            if 'Z' in ts or '+00:00' in ts:
                hh = (hh + 2) % 24
            return f"{hh:02d}:{mm}"
        return "-"
    except:
        return "-"

def safe_string(s: Any, max_len: int = 1000) -> str:
    """Safe string conversion - escapes HTML and JS special chars"""
    if s is None:
        return ""
    text = str(s)[:max_len]
    # Escape backslashes FIRST (before adding any new ones)
    text = text.replace("\\", "&#92;")
    # Escape HTML special chars
    text = text.replace("<", "&lt;").replace(">", "&gt;").replace('"', "&quot;")
    # Escape single quotes for JavaScript onclick handlers
    text = text.replace("'", "&#39;")
    # Escape backticks to prevent JS template literal injection
    text = text.replace("`", "&#96;")
    # Escape newlines/tabs that could break JS strings
    text = text.replace("\n", " ").replace("\r", " ").replace("\t", " ")
    return text

def format_extra_data(data) -> str:
    """Format extra_data dict as nice HTML grid instead of raw JSON"""
    if not data:
        return ""
    
    # Handle string that looks like a dict
    if isinstance(data, str):
        try:
            data = json.loads(data.replace("'", '"'))
        except:
            return f"<p style='font-size:13px;'>{safe_string(data)}</p>"
    
    if not isinstance(data, dict):
        return f"<p style='font-size:13px;'>{safe_string(str(data))}</p>"
    
    # Filter out empty values and format nicely
    items = [(k, v) for k, v in data.items() if v and str(v).strip()]
    if not items:
        return ""
    
    # Group related fields
    html = "<div style='display:grid;grid-template-columns:repeat(auto-fit, minmax(200px, 1fr));gap:10px;'>"
    
    for key, value in items:
        # Make key readable: postal_address_1 → Postal Address 1
        label = key.replace("_", " ").title()
        html += f"""
        <div>
            <span style="color:var(--text-muted);font-size:11px;display:block;">{safe_string(label)}</span>
            <span style="font-size:13px;">{safe_string(str(value))}</span>
        </div>
        """
    
    html += "</div>"
    return html


# 
# EMAIL - Actually send emails
# 

class Email:
    """Email sending functionality"""
    
    @staticmethod
    def send(to_email: str, subject: str, body_html: str, body_text: str = None, business: dict = None, attachments: list = None) -> bool:
        """
        Send an email. attachments: list of dicts with 'filename', 'content' (bytes or str), 'content_type'
        """
        
        # Start with global settings
        smtp_host = SMTP_HOST
        smtp_port = SMTP_PORT
        smtp_user = SMTP_USER
        smtp_pass = SMTP_PASS
        from_email = FROM_EMAIL
        
        # If business provided, try to use its SMTP settings
        if business:
            biz_smtp_host = business.get("smtp_host")
            biz_smtp_user = business.get("smtp_user")
            biz_smtp_pass = business.get("smtp_pass")
            biz_smtp_port = business.get("smtp_port")
            
            # Use business settings if they exist
            if biz_smtp_host and biz_smtp_user and biz_smtp_pass:
                smtp_host = biz_smtp_host
                smtp_user = biz_smtp_user
                smtp_pass = biz_smtp_pass
                smtp_port = int(biz_smtp_port) if biz_smtp_port else 587
                from_email = biz_smtp_user  # Use SMTP user as from email
                logger.info(f"[EMAIL] Using business SMTP: {smtp_host}")
        
        # If no business provided and global not set, try to get current business from session
        if not business and not all([smtp_user, smtp_pass]):
            try:
                current_biz = Auth.get_current_business()
                if current_biz:
                    biz_smtp_host = current_biz.get("smtp_host")
                    biz_smtp_user = current_biz.get("smtp_user")
                    biz_smtp_pass = current_biz.get("smtp_pass")
                    biz_smtp_port = current_biz.get("smtp_port")
                    
                    if biz_smtp_host and biz_smtp_user and biz_smtp_pass:
                        smtp_host = biz_smtp_host
                        smtp_user = biz_smtp_user
                        smtp_pass = biz_smtp_pass
                        smtp_port = int(biz_smtp_port) if biz_smtp_port else 587
                        from_email = biz_smtp_user
                        logger.info(f"[EMAIL] Using current business SMTP: {smtp_host}")
            except Exception as e:
                logger.warning(f"[EMAIL] Could not get business context: {e}")
        
        # Final check - do we have credentials?
        if not all([smtp_user, smtp_pass, from_email]):
            logger.warning("[EMAIL] SMTP not configured - no global or business settings found")
            logger.warning(f"[EMAIL] Debug - Global: SMTP_USER={bool(SMTP_USER)}, SMTP_PASS={bool(SMTP_PASS)}, FROM_EMAIL={bool(FROM_EMAIL)}")
            return False
        
        try:
            msg = MIMEMultipart('mixed')
            msg['Subject'] = subject
            msg['From'] = from_email
            msg['To'] = to_email
            
            body_part = MIMEMultipart('alternative')
            if body_text:
                body_part.attach(MIMEText(body_text, 'plain'))
            body_part.attach(MIMEText(body_html, 'html'))
            msg.attach(body_part)
            
            if attachments:
                from email.mime.base import MIMEBase
                from email import encoders
                for att in attachments:
                    content = att.get('content', b'')
                    if isinstance(content, str):
                        content = content.encode('utf-8')
                    ct = att.get('content_type', 'application/octet-stream')
                    maintype, subtype = ct.split('/', 1) if '/' in ct else ('application', 'octet-stream')
                    part = MIMEBase(maintype, subtype)
                    part.set_payload(content)
                    encoders.encode_base64(part)
                    part.add_header('Content-Disposition', 'attachment', filename=att.get('filename', 'document'))
                    msg.attach(part)
            
            # Send
            logger.info(f"[EMAIL] Attempting to send via {smtp_host}:{smtp_port} as {smtp_user}")
            with smtplib.SMTP(smtp_host, smtp_port, timeout=10) as server:
                server.starttls()
                server.login(smtp_user, smtp_pass)
                server.sendmail(from_email, to_email, msg.as_string())
            
            logger.info(f"[EMAIL] Sent to {to_email}: {subject}")
            return True
            
        except Exception as e:
            logger.error(f"[EMAIL] Failed to send to {to_email}: {e}")
            return False
    
