# 
# DATABASE - Simple wrapper around Supabase
# 

# === STOCK CACHE — avoids 2x Supabase calls per typeahead keystroke ===
_stock_cache = {}   # {biz_id: (timestamp, data)}
_STOCK_CACHE_TTL = 30  # seconds — short enough to stay fresh

# === STOCK CACHE — avoids 2x Supabase calls per typeahead keystroke ===
_stock_cache = {}   # {biz_id: (timestamp, data)}
_STOCK_CACHE_TTL = 30  # seconds — short enough to stay fresh

class DB:
    """
    Minimal database layer. Just stores and retrieves.
    NO business logic here - Zane handles that.
    """
    
    def __init__(self):
        self.url = SUPABASE_URL
        self.headers = {
            "apikey": SUPABASE_KEY,
            "Authorization": f"Bearer {SUPABASE_KEY}",
            "Content-Type": "application/json",
            "Prefer": "return=representation"
        }
    
    def get(self, table: str, filters: dict = None, limit: int = 10000) -> List[dict]:
        """Get records from table"""
        try:
            endpoint = f"{self.url}/rest/v1/{table}?select=*&limit={limit}"
            if filters:
                for k, v in filters.items():
                    endpoint += f"&{k}=eq.{v}"
            
            response = requests.get(endpoint, headers=self.headers, timeout=15)
            if table == "users" and filters:
                print(f"[DB DEBUG] GET {table} filters={filters} → status={response.status_code}, rows={len(response.json()) if response.status_code == 200 else 'N/A'}, body={response.text[:200]}", flush=True)
            return response.json() if response.status_code == 200 else []
        except Exception as e:
            logger.error(f"[DB] Get error on {table}: {e}")
            return []
    
    def get_all_stock(self, business_id: str) -> List[dict]:
        """Get stock from BOTH tables (stock + stock_items) merged.
        stock_items is the newer table used by imports.
        stock is the legacy table used by older features.
        Returns combined list with normalized field names.
        CACHED for 30s to avoid 2x Supabase calls per typeahead keystroke."""
        items = []
        if not business_id:
            return items
        # Check cache first
        now = time.time()
        cached = _stock_cache.get(business_id)
        if cached and (now - cached[0]) < _STOCK_CACHE_TTL:
            return cached[1]
        # Newer table first
        stock_items = self.get("stock_items", {"business_id": business_id})
        if stock_items:
            items.extend(stock_items)
        # Legacy table  
        legacy = self.get("stock", {"business_id": business_id})
        if legacy:
            # Avoid duplicates by code
            existing_codes = {str(s.get("code", "")).lower() for s in items if s.get("code")}
            for s in legacy:
                code = str(s.get("code", "")).lower()
                if not code or code not in existing_codes:
                    items.append(s)
        _stock_cache[business_id] = (now, items)
        return items
    
    def get_one_stock(self, stock_id: str):
        """Get a single stock item - tries stock_items first, then stock"""
        item = self.get_one("stock_items", stock_id)
        if not item:
            item = self.get_one("stock", stock_id)
        return item
    
    def get_business_users(self, business_id: str) -> list:
        """Get all users linked to a business via team_members + owner.
        Returns user records with 'name' field resolved from metadata.
        Falls back to empty list on any error."""
        if not business_id:
            return []
        
        try:
            users = []
            seen_ids = set()
            
            # 1. Get business owner
            try:
                biz = self.get_one("businesses", business_id)
                owner = None
                
                # Try via business.user_id first
                if biz and biz.get("user_id"):
                    owner = self.get_one("users", biz["user_id"])
                
                # Fallback: find user whose default_business_id matches
                if not owner:
                    potential_owners = self.get("users", {"default_business_id": business_id}) or []
                    if potential_owners:
                        owner = potential_owners[0]
                        # Also fix the business record for next time
                        if biz and not biz.get("user_id"):
                            try:
                                self.update("businesses", business_id, {"user_id": owner.get("id")})
                            except:
                                pass
                
                if owner:
                    # Resolve name from metadata if needed
                    if not owner.get("name"):
                        if owner.get("raw_user_meta_data"):
                            try:
                                meta = json.loads(owner["raw_user_meta_data"]) if isinstance(owner["raw_user_meta_data"], str) else owner["raw_user_meta_data"]
                                owner["name"] = meta.get("full_name") or owner.get("email") or "Owner"
                            except:
                                owner["name"] = owner.get("email") or "Owner"
                        else:
                            owner["name"] = owner.get("email") or "Owner"
                    owner["role"] = "owner"
                    users.append(owner)
                    seen_ids.add(owner.get("id"))
                    logger.info(f"[DB] get_business_users found owner: {owner.get('name')}")
                else:
                    logger.warning(f"[DB] get_business_users: no owner found for business {business_id}")
            except Exception as e:
                logger.warning(f"[DB] get_business_users owner lookup failed: {e}")
            
            # 2. Get team members
            try:
                members = self.get("team_members", {"business_id": business_id}) or []
            except:
                members = []
            
            for tm in members:
                try:
                    uid = tm.get("user_id")
                    if uid and uid not in seen_ids:
                        user = self.get_one("users", uid)
                        if user:
                            if not user.get("name"):
                                if user.get("raw_user_meta_data"):
                                    try:
                                        meta = json.loads(user["raw_user_meta_data"]) if isinstance(user["raw_user_meta_data"], str) else user["raw_user_meta_data"]
                                        user["name"] = meta.get("full_name") or user.get("email") or "Staff"
                                    except:
                                        user["name"] = user.get("email") or "Staff"
                                else:
                                    user["name"] = user.get("email") or "Staff"
                            user["role"] = tm.get("role", "staff")
                            users.append(user)
                            seen_ids.add(uid)
                    elif not uid and tm.get("email"):
                        users.append({
                            "id": tm.get("id", ""),
                            "name": tm.get("name", tm.get("email", "Invited")),
                            "email": tm.get("email"),
                            "role": tm.get("role", "staff"),
                            "status": tm.get("status", "pending")
                        })
                except Exception as e:
                    logger.warning(f"[DB] get_business_users member lookup failed: {e}")
                    continue
            
            return users
        except Exception as e:
            logger.error(f"[DB] get_business_users error: {e}")
            return []
    
    def update_stock(self, stock_id: str, updates: dict, biz_id: str = None):
        """Update stock item - FIXED version.
        
        BUG FOUND: stock_items.quantity is INTEGER in Supabase.
        Python sends 5.0 (float) → PostgreSQL rejects with:
        'invalid input syntax for type integer: "5.0"'
        
        FIX: Convert qty to int before sending. Also only sends qty fields
        if they were explicitly in updates (prevents wiping qty on price changes).
        """
        # Invalidate stock cache on any stock update
        if biz_id:
            _stock_cache.pop(biz_id, None)
        
        logger.info(f"[STOCK UPDATE] === START === stock_id={stock_id}, updates={updates}, biz_id={biz_id}")
        
        # Determine if this update includes a quantity change
        has_qty = "quantity" in updates or "qty" in updates
        
        if has_qty:
            # Extract qty - handle 0 correctly (0 is valid, None is not)
            raw_qty = updates.get("quantity")
            if raw_qty is None:
                raw_qty = updates.get("qty")
            if raw_qty is None:
                raw_qty = 0
            # Convert to int for INTEGER columns, but keep precision if fractional
            float_qty = float(raw_qty)
            # If it's a whole number (5.0, 10.0), send as int. Otherwise keep float for NUMERIC columns.
            if float_qty == int(float_qty):
                safe_qty = int(float_qty)
            else:
                safe_qty = float_qty
            logger.info(f"[STOCK UPDATE] Qty: raw={raw_qty} → safe={safe_qty} (type={type(safe_qty).__name__})")
        
        # Build field dict - only include qty if it was in updates
        fields = {}
        if has_qty:
            fields["quantity"] = safe_qty
        
        # Pass through non-qty fields (selling_price, cost_price, description, etc.)
        for k, v in updates.items():
            if k not in ("qty", "quantity"):
                fields[k] = v
        
        if not fields:
            logger.warning(f"[STOCK UPDATE] No fields to update for {stock_id}")
            return False
        
        # === TRY 1: stock_items table ===
        try:
            url = f"{self.url}/rest/v1/stock_items?id=eq.{stock_id}"
            if biz_id:
                url += f"&business_id=eq.{biz_id}"
            
            headers = {**self.headers, "Prefer": "return=representation"}
            
            logger.info(f"[STOCK UPDATE] TRY 1: PATCH stock_items → {fields}")
            resp = requests.patch(url, headers=headers, json=fields, timeout=30)
            logger.info(f"[STOCK UPDATE] TRY 1: status={resp.status_code}, body={resp.text[:300]}")
            
            if resp.status_code == 200:
                result = resp.json()
                if result and len(result) > 0:
                    logger.info(f"[STOCK UPDATE] ✅ SUCCESS! quantity now = {result[0].get('quantity')}")
                    return True
                else:
                    logger.warning(f"[STOCK UPDATE] TRY 1: 200 but empty - ID not found or biz_id mismatch")
            elif resp.status_code == 400 and "22P02" in resp.text:
                # STILL integer type error - force int
                logger.warning(f"[STOCK UPDATE] Integer type error - forcing int conversion")
                if has_qty:
                    fields["quantity"] = int(float_qty)
                resp2 = requests.patch(url, headers=headers, json=fields, timeout=30)
                if resp2.status_code == 200:
                    result = resp2.json()
                    if result and len(result) > 0:
                        logger.info(f"[STOCK UPDATE] ✅ SUCCESS after int() force! quantity now = {result[0].get('quantity')}")
                        return True
        except Exception as e:
            logger.error(f"[STOCK UPDATE] TRY 1 exception: {e}")
        
        # === TRY 2: stock_items WITHOUT biz_id filter (in case of mismatch) ===
        if biz_id:
            try:
                url = f"{self.url}/rest/v1/stock_items?id=eq.{stock_id}"
                headers = {**self.headers, "Prefer": "return=representation"}
                
                # Force int for safety
                safe_fields = dict(fields)
                if has_qty:
                    safe_fields["quantity"] = int(float_qty)
                
                logger.info(f"[STOCK UPDATE] TRY 2: PATCH stock_items (no biz_id) → {safe_fields}")
                resp = requests.patch(url, headers=headers, json=safe_fields, timeout=30)
                logger.info(f"[STOCK UPDATE] TRY 2: status={resp.status_code}, body={resp.text[:300]}")
                
                if resp.status_code == 200:
                    result = resp.json()
                    if result and len(result) > 0:
                        logger.info(f"[STOCK UPDATE] ✅ TRY 2 SUCCESS (no biz_id filter)! biz_id mismatch was the problem")
                        return True
            except Exception as e:
                logger.error(f"[STOCK UPDATE] TRY 2 exception: {e}")
        
        # === TRY 3: legacy 'stock' table with 'qty' column ===
        try:
            legacy_fields = dict(fields)
            if has_qty:
                legacy_fields.pop("quantity", None)
                legacy_fields["qty"] = int(float_qty)
            
            url = f"{self.url}/rest/v1/stock?id=eq.{stock_id}"
            if biz_id:
                url += f"&business_id=eq.{biz_id}"
            headers = {**self.headers, "Prefer": "return=representation"}
            
            logger.info(f"[STOCK UPDATE] TRY 3: PATCH stock (legacy) → {legacy_fields}")
            resp = requests.patch(url, headers=headers, json=legacy_fields, timeout=30)
            
            if resp.status_code == 200:
                result = resp.json()
                if result and len(result) > 0:
                    logger.info(f"[STOCK UPDATE] ✅ TRY 3 SUCCESS (legacy stock table)")
                    return True
        except Exception as e:
            logger.error(f"[STOCK UPDATE] TRY 3 exception: {e}")
        
        logger.error(f"[STOCK UPDATE] ❌ ALL ATTEMPTS FAILED for stock_id={stock_id}")
        return False
    
    def save_stock(self, record: dict):
        """Save stock item to stock_items (preferred table)"""
        # Invalidate stock cache
        _biz = record.get("business_id")
        if _biz:
            _stock_cache.pop(_biz, None)
        return self.save("stock_items", record)
    
    def count(self, table: str, filters: dict = None) -> int:
        """Fast count - doesn't load all data"""
        try:
            endpoint = f"{self.url}/rest/v1/{table}?select=count"
            if filters:
                for k, v in filters.items():
                    endpoint += f"&{k}=eq.{v}"
            
            headers = {**self.headers, "Prefer": "count=exact"}
            response = requests.head(endpoint, headers=headers, timeout=30)
            
            # Count is in the content-range header
            content_range = response.headers.get("content-range", "")
            if "/" in content_range:
                return int(content_range.split("/")[1])
            return 0
        except Exception as e:
            logger.error(f"[DB] Count error: {e}")
            return 0
    
    def sum_column(self, table: str, column: str, filters: dict = None) -> float:
        """Get sum of a column - only loads that column, not all data"""
        try:
            endpoint = f"{self.url}/rest/v1/{table}?select={column}"
            if filters:
                for k, v in filters.items():
                    endpoint += f"&{k}=eq.{v}"
            
            response = requests.get(endpoint, headers=self.headers, timeout=30)
            if response.status_code == 200:
                rows = response.json()
                return sum(float(r.get(column, 0) or 0) for r in rows)
            return 0
        except Exception as e:
            logger.error(f"[DB] Sum error: {e}")
            return 0
    
    def get_columns(self, table: str, columns: list, filters: dict = None, limit: int = 10000) -> List[dict]:
        """Get only specific columns - much faster than select=*"""
        try:
            cols = ",".join(columns)
            endpoint = f"{self.url}/rest/v1/{table}?select={cols}&limit={limit}"
            if filters:
                for k, v in filters.items():
                    endpoint += f"&{k}=eq.{v}"
            
            response = requests.get(endpoint, headers=self.headers, timeout=20)
            return response.json() if response.status_code == 200 else []
        except Exception as e:
            logger.error(f"[DB] Get columns error: {e}")
            return []
    
    def get_one(self, table: str, id: str) -> Optional[dict]:
        """Get single record by ID"""
        results = self.get(table, {"id": id}, limit=1)
        return results[0] if results else None
    
    def save(self, table: str, data: dict) -> Tuple[bool, Any]:
        """Insert or update record - auto-handles unknown column errors (PGRST204)"""
        try:
            if not data.get("id"):
                data["id"] = generate_id()
            if not data.get("created_at"):
                data["created_at"] = now()
            
            # Use on_conflict for proper upsert on id column
            url = f"{self.url}/rest/v1/{table}?on_conflict=id"
            
            response = requests.post(
                url,
                headers={**self.headers, "Prefer": "return=representation,resolution=merge-duplicates"},
                json=data,
                timeout=30
            )
            
            logger.info(f"[DB SAVE] {table} response: {response.status_code} - {response.text[:200]}")
            
            if response.status_code in (200, 201):
                result = response.json()
                return True, result[0] if result else data
            
            # Auto-fix: if column not found (PGRST204), remove offending column and retry
            if response.status_code == 400 and "PGRST204" in response.text:
                try:
                    err_data = response.json()
                    err_msg = err_data.get("message", "")
                    if "Could not find" in err_msg and "column" in err_msg:
                        bad_col = err_msg.split("'")[1]
                        logger.warning(f"[DB SAVE] Column '{bad_col}' not in {table} - removing and retrying")
                        data.pop(bad_col, None)
                        response2 = requests.post(
                            url,
                            headers={**self.headers, "Prefer": "return=representation,resolution=merge-duplicates"},
                            json=data,
                            timeout=30
                        )
                        if response2.status_code in (200, 201):
                            result = response2.json()
                            logger.info(f"[DB SAVE] {table} retry SUCCESS after removing '{bad_col}'")
                            return True, result[0] if result else data
                except Exception as retry_err:
                    logger.error(f"[DB SAVE] Retry failed: {retry_err}")
            
            # Detailed error message
            error_msg = f"HTTP {response.status_code}: {response.text[:300]}"
            logger.error(f"[DB] Save to {table} failed: {error_msg}")
            return False, error_msg
            
        except Exception as e:
            logger.error(f"[DB] Save exception for {table}: {e}")
            return False, str(e)
    
    def save_many(self, table: str, records: List[dict]) -> Tuple[int, int]:
        """Batch save records using bulk insert - 100 at a time"""
        success = 0
        errors = 0
        
        # Process in batches of 100
        batch_size = 100
        for i in range(0, len(records), batch_size):
            batch = records[i:i + batch_size]
            
            try:
                # Supabase bulk insert - POST array of records
                response = requests.post(
                    f"{self.url}/rest/v1/{table}",
                    headers=self.headers,
                    json=batch,
                    timeout=20
                )
                
                if response.status_code in [200, 201]:
                    success += len(batch)
                else:
                    # Fallback to individual inserts for this batch
                    for record in batch:
                        ok, _ = self.save(table, record)
                        if ok:
                            success += 1
                        else:
                            errors += 1
            except Exception as e:
                logger.error(f"[DB] Bulk insert error: {e}")
                # Fallback to individual inserts
                for record in batch:
                    ok, _ = self.save(table, record)
                    if ok:
                        success += 1
                    else:
                        errors += 1
        
        return success, errors
    
    def delete(self, table: str, id: str, business_id: str = None) -> bool:
        """Delete record - with verification"""
        try:
            # Build URL with filters
            url = f"{self.url}/rest/v1/{table}?id=eq.{id}"
            if business_id:
                url += f"&business_id=eq.{business_id}"
            
            # Request return of deleted records to verify
            headers = {**self.headers, "Prefer": "return=representation"}
            response = requests.delete(url, headers=headers, timeout=30)
            
            # Check if anything was actually deleted
            if response.status_code == 200:
                deleted = response.json()
                if deleted and len(deleted) > 0:
                    logger.info(f"[DB DELETE] {table} id={id}: DELETED")
                    return True
                else:
                    logger.warning(f"[DB DELETE] {table} id={id}: Nothing deleted (RLS?)")
                    return False
            elif response.status_code == 204:
                # No content - might have worked, might not
                logger.info(f"[DB DELETE] {table} id={id}: status=204 (assumed ok)")
                return True
            else:
                logger.error(f"[DB DELETE] {table} id={id}: status={response.status_code}")
                return False
                
        except Exception as e:
            logger.error(f"[DB DELETE] Error: {e}")
            return False
    
    def delete_many(self, table: str, ids: list, business_id: str = None) -> Tuple[int, int]:
        """Batch delete multiple records in one API call
        
        ids = ["id1", "id2", "id3", ...]
        Returns: (success_count, failed_count)
        """
        if not ids:
            return (0, 0)
        
        success = 0
        failed = 0
        
        # Process in chunks of 50 to avoid URL length limits
        CHUNK_SIZE = 50
        
        for i in range(0, len(ids), CHUNK_SIZE):
            chunk = ids[i:i + CHUNK_SIZE]
            
            try:
                # Use IN filter: ?id=in.(id1,id2,id3)
                ids_str = ",".join(chunk)
                url = f"{self.url}/rest/v1/{table}?id=in.({ids_str})"
                if business_id:
                    url += f"&business_id=eq.{business_id}"
                
                headers = {**self.headers, "Prefer": "return=representation"}
                response = requests.delete(url, headers=headers, timeout=30)
                
                if response.status_code == 200:
                    deleted = response.json()
                    deleted_count = len(deleted) if deleted else 0
                    success += deleted_count
                    failed += len(chunk) - deleted_count
                    logger.info(f"[DB DELETE_MANY] {table}: {deleted_count}/{len(chunk)} deleted")
                elif response.status_code == 204:
                    # Assume all deleted
                    success += len(chunk)
                    logger.info(f"[DB DELETE_MANY] {table}: {len(chunk)} deleted (204)")
                else:
                    failed += len(chunk)
                    logger.error(f"[DB DELETE_MANY] {table}: status={response.status_code}")
                    
            except Exception as e:
                failed += len(chunk)
                logger.error(f"[DB DELETE_MANY] Error: {e}")
        
        logger.info(f"[DB DELETE_MANY] Total: {success} deleted, {failed} failed")
        return (success, failed)
    
    def update(self, table: str, id: str, data: dict, business_id: str = None) -> bool:
        """Update record - with verification. Auto-handles unknown column errors (PGRST204)."""
        try:
            url = f"{self.url}/rest/v1/{table}?id=eq.{id}"
            if business_id:
                url += f"&business_id=eq.{business_id}"
            
            # Request return of updated records to verify
            headers = {**self.headers, "Prefer": "return=representation"}
            response = requests.patch(url, headers=headers, json=data, timeout=30)
            
            # Check if anything was actually updated
            if response.status_code == 200:
                updated = response.json()
                if updated and len(updated) > 0:
                    logger.info(f"[DB UPDATE] {table} id={id}: UPDATED")
                    return True
                else:
                    logger.warning(f"[DB UPDATE] {table} id={id}: Nothing updated (RLS?)")
                    return False
            elif response.status_code == 204:
                logger.info(f"[DB UPDATE] {table} id={id}: status=204 (assumed ok)")
                return True
            
            # Auto-fix: if column not found (PGRST204), remove it and retry
            if response.status_code == 400 and "PGRST204" in response.text:
                try:
                    err_data = response.json()
                    err_msg = err_data.get("message", "")
                    if "Could not find" in err_msg and "column" in err_msg:
                        bad_col = err_msg.split("'")[1]
                        logger.warning(f"[DB UPDATE] Column '{bad_col}' not in {table} - removing and retrying")
                        data.pop(bad_col, None)
                        if data:
                            response2 = requests.patch(url, headers=headers, json=data, timeout=30)
                            if response2.status_code == 200:
                                updated = response2.json()
                                if updated and len(updated) > 0:
                                    logger.info(f"[DB UPDATE] {table} id={id}: retry SUCCESS after removing '{bad_col}'")
                                    return True
                except Exception as retry_err:
                    logger.error(f"[DB UPDATE] Retry failed: {retry_err}")
            
            logger.error(f"[DB UPDATE] {table} id={id}: status={response.status_code} - {response.text[:100]}")
            return False
                
        except Exception as e:
            logger.error(f"[DB UPDATE] Error: {e}")
            return False
    
    def update_business(self, biz_id: str, user_id: str, data: dict) -> Tuple[bool, str]:
        """Update business - direct PATCH (service key bypasses RLS)"""
        try:
            # Direct update by ID - service key should bypass RLS
            url = f"{self.url}/rest/v1/businesses?id=eq.{biz_id}"
            
            headers = {
                **self.headers,
                "Prefer": "return=representation"
            }
            
            logger.info(f"[DB UPDATE BUSINESS] URL: {url}")
            logger.info(f"[DB UPDATE BUSINESS] Data: {data}")
            
            response = requests.patch(url, headers=headers, json=data, timeout=30)
            
            logger.info(f"[DB UPDATE BUSINESS] Response status: {response.status_code}")
            logger.info(f"[DB UPDATE BUSINESS] Response body: {response.text[:500]}")
            
            if response.status_code == 200:
                updated = response.json()
                if updated and len(updated) > 0:
                    logger.info(f"[DB UPDATE BUSINESS] SUCCESS!")
                    return True, "Saved"
                else:
                    # No rows returned - maybe RLS or ID not found
                    logger.warning(f"[DB UPDATE BUSINESS] No rows returned")
                    return False, "No rows updated - check business ID"
            elif response.status_code == 204:
                # 204 = success but no content
                logger.info(f"[DB UPDATE BUSINESS] 204 No Content (success)")
                return True, "Saved"
            else:
                error_msg = f"HTTP {response.status_code}: {response.text[:300]}"
                logger.error(f"[DB UPDATE BUSINESS] Failed: {error_msg}")
                return False, error_msg
                
        except Exception as e:
            logger.error(f"[DB UPDATE BUSINESS] Exception: {e}")
            return False, str(e)
    
    def update_many(self, table: str, updates: list, business_id: str = None) -> Tuple[int, int]:
        """Batch update multiple records - chunks to avoid URL length limits
        
        updates = [{"id": "xxx", "data": {"field": "value"}}, ...]
        """
        success = 0
        failed = 0
        
        # Group updates by the data being set (e.g., all category=Fasteners together)
        by_data = {}
        for u in updates:
            data_key = json.dumps(u["data"], sort_keys=True)
            if data_key not in by_data:
                by_data[data_key] = []
            by_data[data_key].append(u["id"])
        
        logger.info(f"[DB UPDATE_MANY] {len(updates)} updates grouped into {len(by_data)} batches")
        
        # Max 50 IDs per request to avoid URL length limits (UUIDs are 36 chars each)
        CHUNK_SIZE = 50
        
        for data_key, ids in by_data.items():
            data = json.loads(data_key)
            num_chunks = (len(ids) + CHUNK_SIZE - 1) // CHUNK_SIZE
            
            logger.info(f"[DB UPDATE_MANY] Updating {len(ids)} records with {data} in {num_chunks} chunks")
            
            # Chunk the IDs
            for i in range(0, len(ids), CHUNK_SIZE):
                chunk = ids[i:i + CHUNK_SIZE]
                ids_str = ",".join(chunk)
                url = f"{self.url}/rest/v1/{table}?id=in.({ids_str})"
                if business_id:
                    url += f"&business_id=eq.{business_id}"
                
                try:
                    headers = {**self.headers, "Prefer": "return=representation"}
                    response = requests.patch(url, headers=headers, json=data, timeout=30)
                    
                    if response.status_code == 200:
                        updated = response.json()
                        count = len(updated) if updated else 0
                        success += count
                    else:
                        logger.error(f"[DB UPDATE_MANY] Chunk {i//CHUNK_SIZE + 1}/{num_chunks} failed: status={response.status_code}")
                        failed += len(chunk)
                except Exception as e:
                    logger.error(f"[DB UPDATE_MANY] Chunk error: {e}")
                    failed += len(chunk)
        
        return success, failed
    
    def get_table_schema(self, table: str) -> List[str]:
        """Get column names for a table from Supabase"""
        try:
            # Try to get one record to see column names
            endpoint = f"{self.url}/rest/v1/{table}?limit=1"
            response = requests.get(endpoint, headers=self.headers, timeout=30)
            
            if response.status_code == 200:
                data = response.json()
                if data and len(data) > 0:
                    return list(data[0].keys())
            
            # If no records, try to get schema from error message or use OPTIONS
            options_response = requests.options(
                f"{self.url}/rest/v1/{table}",
                headers=self.headers,
                timeout=30
            )
            # Parse columns from response if available
            return []
        except Exception as e:
            logger.error(f"[DB] Get schema error: {e}")
            return []
    
    def add_column(self, table: str, column_name: str, column_type: str = "text") -> Tuple[bool, str]:
        """
        Add a new column to a Supabase table via SQL.
        column_type can be: text, integer, numeric, boolean, timestamp
        """
        try:
            # Map simple types to PostgreSQL types
            type_map = {
                "text": "TEXT",
                "string": "TEXT",
                "integer": "INTEGER",
                "int": "INTEGER",
                "number": "NUMERIC",
                "numeric": "NUMERIC",
                "float": "NUMERIC",
                "decimal": "NUMERIC",
                "boolean": "BOOLEAN",
                "bool": "BOOLEAN",
                "date": "DATE",
                "datetime": "TIMESTAMP",
                "timestamp": "TIMESTAMP"
            }
            pg_type = type_map.get(column_type.lower(), "TEXT")
            
            # Use Supabase SQL endpoint (requires service role key)
            sql = f"ALTER TABLE {table} ADD COLUMN IF NOT EXISTS {column_name} {pg_type};"
            
            endpoint = f"{self.url}/rest/v1/rpc/exec_sql"
            response = requests.post(
                endpoint,
                headers=self.headers,
                json={"query": sql},
                timeout=30
            )
            
            if response.status_code in (200, 201, 204):
                logger.info(f"[DB] Added column {column_name} ({pg_type}) to {table}")
                return True, f"Added column {column_name}"
            else:
                # Try alternative approach - just save a record with the new field
                # Supabase will accept it if the column exists
                logger.warning(f"[DB] Could not add column via SQL, will try on insert: {response.text[:200]}")
                return False, f"Could not add column: {response.text[:200]}"
                
        except Exception as e:
            logger.error(f"[DB] Add column error: {e}")
            return False, str(e)
    
    def count(self, table: str, filters: dict = None) -> int:
        """Count records"""
        records = self.get(table, filters)
        return len(records)


