@app.route("/api/zane/analyze-file", methods=["POST"])
@login_required
def api_zane_analyze_file():
    """
    Zane File Analysis - Upload CSV/Excel/PDF for AI-powered analysis
    Returns formatted HTML for fullscreen modal display
    Used for Trial Balance analysis, bank statements, any financial document
    Uses Claude Sonnet for analysis via Brain.call
    """
    try:
        file = request.files.get("file")
        if not file:
            return jsonify({"success": False, "error": "No file uploaded"})
        
        filename = file.filename.lower() if file.filename else "file"
        file_data = file.read()
        
        business = Auth.get_current_business()
        biz_name = business.get("name", "Unknown") if business else "Unknown"
        biz_id = business.get("id") if business else None
        
        # ── Gather BUSINESS CONTEXT for smart analysis ──
        biz_context = ""
        try:
            if biz_id:
                from concurrent.futures import ThreadPoolExecutor
                with ThreadPoolExecutor(max_workers=5) as pool:
                    f_stock = pool.submit(db.get_all_stock, biz_id)
                    f_emps = pool.submit(db.get, "employees", {"business_id": biz_id})
                    f_cust = pool.submit(db.get, "customers", {"business_id": biz_id})
                    f_inv = pool.submit(db.get, "invoices", {"business_id": biz_id})
                    f_exp = pool.submit(db.get, "expenses", {"business_id": biz_id})
                
                stock = f_stock.result(timeout=10) or []
                emps = f_emps.result(timeout=10) or []
                custs = f_cust.result(timeout=10) or []
                invoices = f_inv.result(timeout=10) or []
                expenses = f_exp.result(timeout=10) or []
                
                total_stock_value = sum(float(s.get("qty") or s.get("quantity") or 0) * float(s.get("cost") or s.get("cost_price") or 0) for s in stock)
                total_stock_selling = sum(float(s.get("qty") or s.get("quantity") or 0) * float(s.get("price") or s.get("selling_price") or 0) for s in stock)
                stock_count = len(stock)
                emp_count = len(emps)
                customer_count = len(custs)
                monthly_salaries = sum(float(e.get("basic_salary") or 0) for e in emps)
                
                # Revenue estimate from last 3 months invoices + sales
                from datetime import timedelta
                three_months_ago = (datetime.utcnow() - timedelta(days=90)).strftime("%Y-%m-%d")
                recent_inv = [i for i in invoices if (i.get("date") or "") >= three_months_ago]
                recent_exp = [e for e in expenses if (e.get("date") or "") >= three_months_ago]
                quarterly_revenue = sum(float(i.get("total") or 0) for i in recent_inv)
                quarterly_expenses = sum(float(e.get("amount") or e.get("total") or 0) for e in recent_exp)
                monthly_revenue = quarterly_revenue / 3 if quarterly_revenue > 0 else 0
                monthly_expenses = quarterly_expenses / 3 if quarterly_expenses > 0 else 0
                
                total_debtors = sum(v for v in calc_all_customer_balances(biz_id).values() if v > 0)
                
                biz_context = f"""
BUSINESS PROFILE FOR {biz_name}:
- Stock: {stock_count} items, cost value R{total_stock_value:,.0f}, selling value R{total_stock_selling:,.0f}
- Employees: {emp_count}, total monthly salaries R{monthly_salaries:,.0f}
- Customers: {customer_count}, outstanding debtors R{total_debtors:,.0f}
- Est. monthly revenue: R{monthly_revenue:,.0f} (last 3 months avg)
- Est. monthly expenses: R{monthly_expenses:,.0f} (last 3 months avg)
- Est. monthly gross profit: R{monthly_revenue - monthly_expenses:,.0f}
- Annual turnover estimate: R{monthly_revenue * 12:,.0f}
"""
                logger.info(f"[ANALYZE] Business context loaded: stock R{total_stock_value:,.0f}, {emp_count} emps, revenue R{monthly_revenue:,.0f}/mo")
        except Exception as ctx_err:
            logger.warning(f"[ANALYZE] Business context failed (non-critical): {ctx_err}")
            biz_context = f"Business: {biz_name} (detailed data unavailable)"
        
        
        # ── Read file content based on type ──
        file_text = ""
        file_type = "unknown"
        
        if filename.endswith('.csv'):
            file_type = "CSV"
            try:
                file_text = file_data.decode('utf-8')
            except:
                file_text = file_data.decode('latin-1')
        
        elif filename.endswith(('.xlsx', '.xls')):
            file_type = "Excel"
            try:
                import openpyxl
                wb = openpyxl.load_workbook(io.BytesIO(file_data), data_only=True)
                rows = []
                for sheet_name in wb.sheetnames:
                    ws = wb[sheet_name]
                    if len(wb.sheetnames) > 1:
                        rows.append(f"--- Sheet: {sheet_name} ---")
                    for row in ws.iter_rows(values_only=True):
                        row_vals = [str(cell) if cell is not None else "" for cell in row]
                        rows.append(",".join(row_vals))
                file_text = "\n".join(rows)
            except Exception as e:
                return jsonify({"success": False, "error": f"Could not read Excel file: {e}"})
        
        elif filename.endswith('.pdf'):
            file_type = "PDF"
            # For PDFs, use Claude Sonnet vision
            base64_data = base64.b64encode(file_data).decode('utf-8')
            
            client = _anthropic_client
            message = client.messages.create(
                model="claude-sonnet-4-6",
                max_tokens=6000,
                messages=[{
                    "role": "user",
                    "content": [
                        {"type": "document", "source": {"type": "base64", "media_type": "application/pdf", "data": base64_data}},
                        {"type": "text", "text": f"""You are Zane, the senior AI business advisor for {biz_name}. You have a BCom Honours and MBA with 15 years SA SME experience. You are NOT a chatbot — you are the advisor that businesses pay R2,000/hour for.

STEP 1 — IDENTIFY the document type:
- Financial: Trial Balance, Income Statement, Balance Sheet, Bank Statement, VAT Return
- Insurance: Policy schedule, cover summary, renewal notice, claim form
- Legal: Contract, lease agreement, terms & conditions, employment contract
- HR: Employment contract, disciplinary notice, CCMA referral, letter of demand
- Tax: SARS assessment, IRP6, IT14, tax certificate
- Other: Quote, proposal, letter, report

STEP 2 — ANALYZE based on type:

FOR INSURANCE POLICIES — This is where you shine. Compare against the ACTUAL business data:
{biz_context}

Check EVERY one of these:
- Is stock/contents cover adequate? (compare insured value vs actual R{total_stock_value:,.0f} stock at cost)
- Is business interruption cover enough? (compare indemnity vs actual monthly gross profit)
- Is there public liability? (essential for walk-in businesses)
- Is there employer's liability? (they have {emp_count} employees)
- Are vehicle values current or outdated?
- What is the excess per claim? Is it reasonable?
- Are there dangerous exclusions? (vacancy clause, load shedding, riot/strike)
- Is the premium reasonable for the cover?
- What's MISSING that they SHOULD have?
- What are they paying for that they DON'T need?
Flag every gap with a RED warning. Flag every saving opportunity with GREEN.

FOR CONTRACTS/LEASES — Review like a lawyer:
- Identify unfair or one-sided terms
- Check cancellation clauses and notice periods
- Highlight penalty clauses and escalation rates
- Flag missing essential clauses
- Check CPA/BCEA compliance where applicable
- Plain language assessment
- Overall risk rating (Low/Medium/High)

FOR FINANCIAL DOCUMENTS — Analyze as before:
- Read totals AS PRINTED (do not calculate)
- Identify concerns, errors, unusual items
- Compare against business context data

{biz_context}

STEP 3 — OUTPUT as clean HTML:
Use <h4> for sections, <table> for data, <p> for text.
Use these styled divs for findings:
- <div style="background:#fee2e2;border-left:4px solid #ef4444;padding:12px;border-radius:6px;margin:8px 0;"><b>RISK:</b> [finding]</div> for dangers/gaps
- <div style="background:#fef3c7;border-left:4px solid #f59e0b;padding:12px;border-radius:6px;margin:8px 0;"><b>WARNING:</b> [finding]</div> for concerns
- <div style="background:#d1fae5;border-left:4px solid #10b981;padding:12px;border-radius:6px;margin:8px 0;"><b>SAVING:</b> [finding]</div> for savings/good points
- <div style="background:#dbeafe;border-left:4px solid #3b82f6;padding:12px;border-radius:6px;margin:8px 0;"><b>TIP:</b> [advice]</div> for recommendations

End with a SUMMARY section: Overall assessment, top 3 actions to take, and estimated financial impact.

Be direct. Be specific. Use actual numbers from both the document AND the business data. This is what makes you worth R2,000/hour — you don't give generic advice, you give advice specific to THIS business."""}
                    ]
                }]
            )
            
            analysis_html = message.content[0].text.strip()
            analysis_html = analysis_html.replace("```html", "").replace("```", "").strip()
            
            return jsonify({
                "success": True,
                "title": f"📄 {file.filename or 'PDF'} Analysis",
                "analysis_html": analysis_html
            })
        
        else:
            return jsonify({"success": False, "error": "Unsupported file type. Use CSV, Excel (.xlsx), or PDF."})
        
        # ── Truncate if too large ──
        if len(file_text) > 50000:
            file_text = file_text[:50000] + "\n... (truncated - file too large for full analysis)"
        
        if not file_text.strip():
            return jsonify({"success": False, "error": "File appears to be empty"})
        
        # ── Count rows for context ──
        row_count = len(file_text.strip().split('\n'))
        
        # ═══════════════════════════════════════════════════════════════════════
        # PYTHON CALCULATES TOTALS - NOT AI!
        # ═══════════════════════════════════════════════════════════════════════
        python_totals = ""
        try:
            lines = file_text.strip().split('\n')
            if len(lines) > 1:
                # Try to detect if this is a TB or financial data
                header = lines[0].lower()
                has_debit_credit = 'debit' in header and 'credit' in header
                
                if has_debit_credit:
                    # Parse as TB - find debit/credit columns
                    headers = [h.strip().lower() for h in lines[0].split(',')]
                    debit_col = None
                    credit_col = None
                    
                    for i, h in enumerate(headers):
                        if 'debit' in h:
                            debit_col = i
                        if 'credit' in h:
                            credit_col = i
                    
                    if debit_col is not None and credit_col is not None:
                        total_debit = 0
                        total_credit = 0
                        account_count = 0
                        
                        for line in lines[1:]:
                            cols = line.split(',')
                            if len(cols) > max(debit_col, credit_col):
                                try:
                                    dr = cols[debit_col].replace('R', '').replace(' ', '').replace(',', '').strip()
                                    cr = cols[credit_col].replace('R', '').replace(' ', '').replace(',', '').strip()
                                    
                                    if dr and dr not in ('-', '', '0', '0.00'):
                                        total_debit += abs(float(dr))
                                    if cr and cr not in ('-', '', '0', '0.00'):
                                        total_credit += abs(float(cr))
                                    account_count += 1
                                except:
                                    pass
                        
                        difference = abs(total_debit - total_credit)
                        is_balanced = difference < 0.01
                        
                        python_totals = f"""
═══════════════════════════════════════════════════════════════════════
PYTHON-CALCULATED TOTALS (100% ACCURATE - DO NOT RECALCULATE!)
═══════════════════════════════════════════════════════════════════════
Total Accounts: {account_count}
Total Debits:   R {total_debit:,.2f}
Total Credits:  R {total_credit:,.2f}
Difference:     R {difference:,.2f}
Status:         {'✅ BALANCED' if is_balanced else '❌ UNBALANCED - CRITICAL ERROR!'}
═══════════════════════════════════════════════════════════════════════
USE THESE EXACT NUMBERS IN YOUR ANALYSIS. DO NOT CALCULATE YOUR OWN.
"""
                        logger.info(f"[ZANE ANALYZE] Python calculated: Dr={total_debit:.2f} Cr={total_credit:.2f} Bal={'YES' if is_balanced else 'NO'}")
        except Exception as calc_err:
            logger.warning(f"[ZANE ANALYZE] Could not pre-calculate totals: {calc_err}")
        
        # ── Send to AI for ANALYSIS ONLY (not calculation) ──
        analysis_prompt = f"""Analyze this {file_type} file ({row_count} rows) for {biz_name}. Identify what it is (Trial Balance, Chart of Accounts, Bank Statement, Customer List, etc).

{python_totals}

FILE CONTENT:
{file_text}

CRITICAL INSTRUCTION:
═══════════════════════════════════════════════════════════════════════
IF PYTHON TOTALS ARE PROVIDED ABOVE, USE THOSE EXACT NUMBERS!
DO NOT CALCULATE OR RECALCULATE ANY TOTALS YOURSELF!
The totals provided by Python are 100% mathematically accurate.
Your job is to EXPLAIN the data, not to calculate it.
═══════════════════════════════════════════════════════════════════════

Provide your analysis as clean HTML (no markdown, no code fences). Use:
- <h4> for section headers
- <table> with proper <th> and <td> for data tables - include ALL rows from the data in your table
- <p> for explanations
- <span class="amount-dr"> for debit amounts, <span class="amount-cr"> for credit amounts
- <b> for important findings

Include:
1. <h4>📋 Document Type</h4> - What this file is and the period it covers
2. <h4>📊 Summary</h4> - USE THE PYTHON-CALCULATED TOTALS ABOVE (if provided). Just explain what they mean.
3. <h4>📑 Full Data</h4> - Show ALL the data in a nicely formatted table
4. <h4>⚠️ Issues & Observations</h4> - Any errors, missing info, unusual items
5. <h4>💡 Recommendations</h4> - What to do next, any improvements needed

Use ZAR (R) currency format. Be thorough and professional. Return ONLY HTML, no markdown."""
        
        system_prompt = f"""You are Zane, the AI financial analyst for {biz_name}. 

CRITICAL RULE: If Python-calculated totals are provided in the user message, you MUST use those exact numbers. DO NOT calculate totals yourself - Python's calculations are mathematically correct. Your job is to EXPLAIN and ANALYZE the data, not to add numbers.

You analyze financial documents and provide clear, professional analysis in HTML format. You are thorough, accurate, and highlight any issues."""
        
        analysis_html = Brain.call(
            system=system_prompt,
            user=analysis_prompt,
            model=Brain.MODEL_SONNET,  # Use Claude Sonnet for analysis
            max_tokens=4000
        )
        
        if not analysis_html:
            return jsonify({"success": False, "error": "AI analysis failed - please try again"})
        
        # Clean any markdown code fences that might slip through
        analysis_html = analysis_html.replace("```html", "").replace("```", "").strip()
        
        return jsonify({
            "success": True,
            "title": f"📊 {file.filename or file_type} Analysis",
            "analysis_html": analysis_html
        })
        
        
    except Exception as e:
        logger.error(f"[ZANE ANALYZE] Error: {e}")
        return jsonify({"success": False, "error": str(e)})


@app.route("/api/ai", methods=["POST"])
def api_ai():
    """THE BRAIN - Main AI endpoint with conversation memory"""
    
    try:
        user = Auth.get_current_user()
        business = Auth.get_current_business()
        
        if not user:
            return jsonify({"error": "Not logged in"})
        
        # Zane access: managers, admin, owner only
        role = get_user_role()
        if role in ("staff", "cashier", "pos_only", "waiter", "sales"):
            return jsonify({"response": "Zane is only available for managers and admin. Contact your manager if you need help."})
        
        
        data = request.get_json()
        command = data.get("command", "") if data else ""
        
        if not command:
            return jsonify({"error": "No command"})
        
        user_id = user.get("id", "")
        biz_id = business.get("id", "") if business else ""
        
        # Clear chat command
        if command.strip().lower() in ["clear", "reset", "clear chat", "nuwe chat", "begin oor"]:
            chat_key = f"zane_chat_{biz_id}" if biz_id else "zane_chat"
            session.pop(chat_key, None)
            if biz_id and user_id:
                try:
                    ZaneMemory.clear(biz_id, user_id)
                except:
                    pass
            return jsonify({"response": "Chat cleared. Ask me anything!", "actions_taken": [], "data": {}, "suggestions": []})
        
        # ═══════════════════════════════════════════════════════════
        # PERSISTENT MEMORY - Load from DB, merge with session
        # ═══════════════════════════════════════════════════════════
        chat_key = f"zane_chat_{biz_id}" if biz_id else "zane_chat"
        
        # Clean up old session chat data (was causing cookie to exceed 4KB limit)
        session.pop(chat_key, None)
        session.pop("zane_chat_before", None)
        
        # Load chat history from DB (not session — session cookie can't handle it)
        session_history = []
        if biz_id and user_id:
            db_history = ZaneMemory.load(biz_id, user_id)
            if db_history:
                session_history = db_history
                logger.info(f"[ZANE] Loaded {len(db_history)} messages from DB memory")
        
        # Filter out stale/lazy responses from history before passing to AI
        bad_phrases = ["soos hierbo", "as shown above", "gelewer soos", "oorsig gelewer", "already provided", "hierbo"]
        clean_history = []
        for msg in session_history:
            content = msg.get("content", "")
            if msg.get("role") == "assistant" and any(p in content.lower() for p in bad_phrases):
                continue  # Skip lazy AI responses
            clean_history.append(msg)
        
        chat_history = clean_history
        
        # Get context
        context = Context.get_full_context(user, business)
        
        # Add user role for access control (from team_members or owner)
        context["user_role"] = get_user_role()
        
        # === GROUP MODE: Check if user has linked businesses ===
        if BUSINESS_GROUPS_LOADED:
            try:
                groups = BusinessGroupManager.get_my_groups(db, user_id)
                if groups:
                    context["has_groups"] = True
                    context["group_count"] = len(groups)
                    context["group_id"] = groups[0].get("id", "")
                    # Check if message is about cross-business topics — inject full context
                    msg_lower = command.lower()
                    group_triggers = [
                        # English
                        "group", "businesses", "compare", "cross-business", "overall",
                        "all of them", "both", "potential", "perform", "focus",
                        "which one", "which business", "strongest", "weakest", "better",
                        "worse", "revenue across", "total revenue", "combined",
                        "opportunities", "risks", "cash flow across", "struggling",
                        "growing", "attention", "priority", "invest", "expand",
                        "consolidate", "together", "portfolio", "my companies",
                        "steel suppliers", "fulltech", "stainless",
                        # Afrikaans
                        "besighede", "vergelyk", "watter een", "albei", "potensiaal",
                        "presteer", "fokus", "almal", "al my", "sterkste", "swakste",
                        "beter", "slegter", "geleenthede", "risiko", "kontantvloei",
                        "sukkel", "groei", "aandag", "prioriteit", "belê", "uitbrei",
                        "saam", "portefeulje", "kort kom", "kortkom", "meeste",
                    ]
                    if any(t in msg_lower for t in group_triggers):
                        group_ctx = BusinessGroupManager.build_group_context(db, groups[0]['id'], user_id)
                        if group_ctx:
                            context["group_context"] = group_ctx
                            logger.info(f"[ZANE-GROUP] Injected full group context for: {command[:50]}")
            except Exception as e:
                logger.error(f"[ZANE-GROUP] Error checking groups: {e}")
        
        # Add chat history to context for Zane to see
        context["chat_history"] = chat_history[-8:]  # Last 4 exchanges
        
        # ═══════════════════════════════════════════════════════════
        # ZANE'S EYES - He can see where user is and what's happening!
        # ═══════════════════════════════════════════════════════════
        
        # 1. Current page - where is the user right now?
        current_page = data.get("current_page", "")
        context["current_page"] = current_page
        
        # 2. Import context - what happened with their last import attempt?
        import_context = session.get("zane_import_context", {})
        if import_context:
            context["import_context"] = import_context
        
        # 3. Last error - did something go wrong?
        last_error = session.get("zane_last_error", "")
        if last_error:
            context["last_error"] = last_error
            session.pop("zane_last_error", None)  # Clear after reading
        
        # 4. Pending delete - was a delete awaiting confirmation?
        pending_delete = session.get("zane_pending_delete", {})
        if pending_delete:
            context["pending_delete"] = pending_delete
        
        # Let Zane think
        result = Brain.think(command, context)
        
        # Strip emojis from response (safety net - Sonnet sometimes ignores instructions)
        if result.get("response"):
            import re as _re
            result["response"] = _re.sub(r'[\U0001F300-\U0001F9FF\U0001FA00-\U0001FA6F\U0001FA70-\U0001FAFF\u2600-\u27BF\u2B50\u2B55\u26A0\u2705\u274C\u274E\u2714\u2716\u2728\u2753\u2754\u2755\u2757\u2763\u2764\u203C\u2049\u200D\u20E3\uFE0F]', '', result["response"])
        
        # Store pending delete data in session for confirmation flow
        if result.get("data", {}).get("pending_delete"):
            session["zane_pending_delete"] = result["data"]
            logger.info(f"[ZANE] Stored pending delete: {result['data']}")
        elif result.get("actions_taken"):
            # Action was executed - clear any pending delete
            session.pop("zane_pending_delete", None)
        
        # Save to chat history — SESSION-FREE, DB has full history via ZaneMemory
        chat_history.append({"role": "user", "content": command[:200]})
        response_text = result.get("response", "")
        if response_text:
            chat_history.append({"role": "assistant", "content": response_text[:200]})
        
        # Do NOT store chat in session — it bloats the cookie past 4KB limit
        # which causes browser to drop the cookie → auth fails → Pulse hangs
        # Full history is loaded from DB via ZaneMemory.load() at top of this function
        session.permanent = True
        
        # ═══════════════════════════════════════════════════════════
        # SAVE TO PERSISTENT DB MEMORY (async-safe, non-blocking)
        # ═══════════════════════════════════════════════════════════
        if biz_id and user_id and response_text:
            try:
                ZaneMemory.save_exchange(biz_id, user_id, command, response_text[:1000])
            except Exception as mem_err:
                logger.warning(f"[ZANE] Memory save failed (non-critical): {mem_err}")
        
        return jsonify(result)
    except Exception as e:
        logger.error(f"[AI] Error: {e}")
        return jsonify({"error": str(e), "response": f"Sorry, something went wrong: {str(e)}"})


