@app.route("/api/stock-dedup", methods=["POST"])
@login_required
def api_stock_dedup():
    """Remove duplicate stock items across both tables, keep the oldest"""
    user = Auth.get_current_user()
    business = Auth.get_current_business()
    biz_id = business.get("id") if business else None
    
    if not biz_id:
        return jsonify({"error": "No business"})
    
    # Get from BOTH tables
    stock_items = db.get("stock_items", {"business_id": biz_id}) or []
    stock_legacy = db.get("stock", {"business_id": biz_id}) or []
    
    deleted_items = 0
    deleted_legacy = 0
    
    # 1. Dedup within stock_items table
    by_code = {}
    for s in stock_items:
        code = str(s.get("code", "")).lower().strip()
        if not code:
            continue
        if code not in by_code:
            by_code[code] = []
        by_code[code].append(s)
    
    for code, items in by_code.items():
        if len(items) <= 1:
            continue
        items.sort(key=lambda x: x.get("created_at", "9999"))
        for dup in items[1:]:
            db.delete("stock_items", dup["id"], biz_id)
            deleted_items += 1
    
    # 2. Delete legacy stock items that also exist in stock_items
    remaining_items = db.get("stock_items", {"business_id": biz_id}) or []
    item_codes = {str(s.get("code", "")).lower().strip() for s in remaining_items if s.get("code")}
    
    for s in stock_legacy:
        code = str(s.get("code", "")).lower().strip()
        if code and code in item_codes:
            # Duplicate in legacy table - delete it
            db.delete("stock", s["id"], biz_id)
            deleted_legacy += 1
    
    # 3. Also dedup within legacy table
    legacy_by_code = {}
    remaining_legacy = db.get("stock", {"business_id": biz_id}) or []
    for s in remaining_legacy:
        code = str(s.get("code", "")).lower().strip()
        if not code:
            continue
        if code not in legacy_by_code:
            legacy_by_code[code] = []
        legacy_by_code[code].append(s)
    
    for code, items in legacy_by_code.items():
        if len(items) <= 1:
            continue
        items.sort(key=lambda x: x.get("created_at", "9999"))
        for dup in items[1:]:
            db.delete("stock", dup["id"], biz_id)
            deleted_legacy += 1
    
    final_count = len(db.get_all_stock(biz_id))
    
    return jsonify({
        "success": True,
        "deleted_from_stock_items": deleted_items,
        "deleted_from_stock_legacy": deleted_legacy,
        "total_deleted": deleted_items + deleted_legacy,
        "remaining": final_count
    })


# ═══════════════════════════════════════════════════════════════
# PWA — SERVICE WORKER & MANIFEST (Offline POS Capability)
# ═══════════════════════════════════════════════════════════════

@app.route("/sw.js")
def service_worker():
    """Service Worker for offline POS capability"""
    sw_js = """
const CACHE_NAME = 'clickai-pos-v5';
const OFFLINE_URLS = ['/pos'];

// Install — only cache POS (not all pages — that blocks the single server worker)
self.addEventListener('install', event => {
    event.waitUntil(
        caches.open(CACHE_NAME).then(cache => {
            console.log('[SW] Caching POS for offline');
            return cache.addAll(OFFLINE_URLS);
        }).catch(err => console.log('[SW] Cache failed:', err))
    );
    self.skipWaiting();
});

// Activate — clean old caches
self.addEventListener('activate', event => {
    event.waitUntil(
        caches.keys().then(keys => {
            return Promise.all(
                keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k))
            );
        })
    );
    self.clients.claim();
});

// Fetch — network first, cache fallback for POS page
self.addEventListener('fetch', event => {
    const url = new URL(event.request.url);
    
    // Only intercept same-origin navigation requests
    if (url.origin !== location.origin) return;
    
    // For POS page — network first, cache fallback (offline POS)
    const cachedPaths = ['/pos'];
    if (cachedPaths.includes(url.pathname)) {
        event.respondWith(
            fetch(event.request).then(response => {
                // Cache the fresh version
                const clone = response.clone();
                caches.open(CACHE_NAME).then(cache => cache.put(event.request, clone));
                return response;
            }).catch(() => {
                console.log('[SW] Offline — serving cached POS page');
                return caches.match(event.request).then(cached => {
                    return cached || new Response(
                        '<html><body style=\"background:#1a1a2e;color:white;text-align:center;padding:50px;font-family:Arial;\"><h1>Click AI - Offline</h1><p>POS page not cached yet. Connect to internet first, open POS, then offline will work.</p></body></html>',
                        {headers: {'Content-Type': 'text/html'}}
                    );
                });
            })
        );
        return;
    }
    
    // For API calls — always network (offline queue handles failures in JS)
    if (url.pathname.startsWith('/api/')) return;
    
    // For all other pages — network first, no cache fallback
    // (we only cache POS for offline)
});

// Listen for sync events
self.addEventListener('message', event => {
    if (event.data && event.data.type === 'CACHE_POS') {
        caches.open(CACHE_NAME).then(cache => {
            cache.add('/pos').then(() => console.log('[SW] POS page cache refreshed'));
        });
    }
});
"""
    return Response(sw_js, mimetype='application/javascript',
                    headers={'Service-Worker-Allowed': '/', 'Cache-Control': 'no-cache'})


