def jarvis_hud_item(label, value, dot_color="c", val_color="", side="L", accent=""):
    """Build a single HUD flank item"""
    vc = f" {val_color}" if val_color else ""
    ac = f" {accent}" if accent else ""
    return f'<div class="j-fi{ac} {side}"><div class="j-fr"><div class="j-fd {dot_color}"></div><span class="j-fl">{label}</span><span class="j-fv{vc}">{value}</span></div></div>'


def jarvis_hud_header(page_name, page_count, left_items, right_items, reactor_size="page", alert_html=""):
    """
    Build the Jarvis HUD header with reactor + flanking stats + Zane extension chat.
    Everything is wrapped in one unified HUD container.
    """
    # Build left flank
    left_html = ""
    for i, item in enumerate(left_items):
        label, value, dot, vc, ac = (list(item) + ["", "", ""])[:5]
        left_html += jarvis_hud_item(label, value, dot or "c", vc, "L", ac)
        if i < len(left_items) - 1 and i % 2 == 1:
            left_html += '<div class="j-fln"></div>'
    
    # Build right flank
    right_html = ""
    for i, item in enumerate(right_items):
        label, value, dot, vc, ac = (list(item) + ["", "", ""])[:5]
        right_html += jarvis_hud_item(label, value, dot or "c", vc, "R", ac)
        if i < len(right_items) - 1 and i % 2 == 1:
            right_html += '<div class="j-fln"></div>'
    
    return f'''
    <div class="j-hud-wrap" data-page="{page_name}">
        <div class="j-hero" style="padding:14px 20px 0;">
            <div class="j-flank">{left_html}</div>
            <div class="j-cn"></div>
            <div class="j-rx {reactor_size}" onclick="jzToggle()" style="z-index:10;">
                <div class="j-rg r1"></div>
                <div class="j-rg r2"></div>
                <div class="j-rg r3"></div>
                <div class="j-rg r4"></div>
                <div class="j-core">
                    <div class="j-brand">CLICK.AI</div>
                    <div class="j-sub">// BUSINESS INTELLIGENCE</div>
                    <div class="j-ai">ZANE AI</div>
                </div>
                <div class="j-hint">CLICK TO TALK TO ZANE</div>
            </div>
            <div class="j-cn R"></div>
            <div class="j-flank">{right_html}</div>
            <div class="j-plbl">
                <div class="j-pn">{page_name}</div>
                <div class="j-pc">{page_count}</div>
            </div>
        </div>
        <div class="j-hud-pad" id="jHudPad"></div>
        <div class="j-zane-ext" id="jZaneExt">
            <div class="j-scanline"></div>
            <div class="j-zane-ctx">
                <div class="jzc-left">
                    <span class="jzc-ci"><span class="jzd"></span>{page_name}</span>
                    <span class="jzc-ci"><span class="jzd"></span>AI READY</span>
                </div>
                <button class="jzc-close" onclick="jzToggle()">CLOSE [ESC]</button>
            </div>
            <div class="j-zane-layout">
                <div class="j-zane-left">
                    <div class="j-zane-msgs" id="jzMsgsL"></div>
                </div>
                <div class="j-zane-center">
                    <div class="jzc-label">ZANE AI</div>
                    <div class="jzc-status">ONLINE</div>
                    <div class="jzc-actions">
                        <button class="jzc-btn" onclick="jzSend('Give me a business summary')">Business Summary</button>
                        <button class="jzc-btn" onclick="jzSend('Who owes me the most?')">Top Debtors</button>
                        <button class="jzc-btn" onclick="jzSend('Show low stock items')">Low Stock</button>
                        <button class="jzc-btn" onclick="jzSend('Run business pulse')">Run Pulse</button>
                        <button class="jzc-btn" onclick="jzSend('Cash flow forecast')">Cash Flow</button>
                        <button class="jzc-btn" onclick="jzSend('Create new invoice')">New Invoice</button>
                    </div>
                </div>
                <div class="j-zane-right">
                    <div class="j-zane-msgs" id="jzMsgsR"></div>
                </div>
            </div>
            <div class="j-zane-inp">
                <input type="text" placeholder="Ask Zane anything..." id="jzInput" onkeydown="if(event.key==='Enter'){{jzSend(this.value);this.value=''}}">
                <button class="jzs" onclick="jzSend(document.getElementById('jzInput').value);document.getElementById('jzInput').value=''">SEND</button>
            </div>
        </div>
    </div>
    {alert_html}
    <script>
    function jzToggle(){{
        var ext=document.getElementById('jZaneExt');
        var pad=document.getElementById('jHudPad');
        ext.classList.toggle('open');
        if(pad)pad.style.display=ext.classList.contains('open')?'none':'';
        if(ext.classList.contains('open')){{
            setTimeout(function(){{document.getElementById('jzInput').focus();}},400);
            if(!document.getElementById('jzMsgsL').children.length){{
                document.getElementById('jzMsgsL').innerHTML='<div class="jzm-ai"><p>Hello! I\\'m <strong>Zane</strong>, your AI business assistant. Ask me anything about your data, or use the quick actions.</p></div>';
                document.getElementById('jzMsgsR').innerHTML='<div class="jzm-ai"><p><strong>Quick insights loading...</strong></p><p>Click a quick action or ask me a question to get started.</p></div>';
            }}
        }}
    }}
    async function jzSend(text){{
        if(!text||!text.trim())return;
        var msgsL=document.getElementById('jzMsgsL');
        var msgsR=document.getElementById('jzMsgsR');
        var input=document.getElementById('jzInput');
        msgsL.innerHTML+='<div class="jzm-user"><p>'+text+'</p></div>';
        msgsL.scrollTop=msgsL.scrollHeight;
        input.value='';
        msgsR.innerHTML='<div class="jzm-ai"><p style="opacity:0.6;">⟳ Processing...</p></div>';
        try {{
            var resp=await fetch('/api/ai',{{
                method:'POST',
                headers:{{'Content-Type':'application/json'}},
                body:JSON.stringify({{command:text,current_page:window.location.pathname}})
            }});
            var data=await resp.json();
            var reply=data.response||data.error||'Sorry, I had trouble with that.';
            var h=reply;
            h=h.replace(/\\*\\*(.+?)\\*\\*/g,'<strong>$1</strong>');
            h=h.replace(/\\*(.+?)\\*/g,'<em>$1</em>');
            h=h.replace(/^- (.+)$/gm,'<li>$1</li>');
            h=h.replace(/\\n\\n/g,'</p><p style="margin:6px 0;">');
            h=h.replace(/\\n/g,'<br>');
            h='<p style="margin:6px 0;">'+h+'</p>';
            msgsR.innerHTML='<div class="jzm-ai">'+h+'</div>';
            msgsR.scrollTop=msgsR.scrollHeight;
            msgsL.scrollTop=msgsL.scrollHeight;
            if(data.navigate&&!data.error){{
                var target=data.navigate;
                if(target&&target.startsWith('/')&&target!==window.location.pathname){{
                    if(data.highlight)localStorage.setItem('zane_highlight',data.highlight);
                    if(data.next_message)localStorage.setItem('zane_next_message',data.next_message);
                    setTimeout(function(){{window.location.href=target;}},1500);
                }}
            }}
        }} catch(e) {{
            msgsR.innerHTML='<div class="jzm-ai"><p style="color:var(--danger,#ff4466);">Error connecting to Zane. Try again.</p></div>';
        }}
    }}
    document.addEventListener('keydown',function(e){{if(e.key==='Escape'){{var ext=document.getElementById('jZaneExt');if(ext&&ext.classList.contains('open'))jzToggle();}}}});
    </script>
    '''


def jarvis_techline(extra=""):
    """Build the bottom tech line"""
    extra_span = f'<span>{extra}</span>' if extra else ''
    return f'''<div class="j-tl"><span>SYS <b>ONLINE</b></span><span>DB <b>CONNECTED</b></span><span>AI <b>ACTIVE</b></span><span>ZANE <b>READY</b></span>{extra_span}</div>'''


def is_jarvis():
    """Check if current theme is Jarvis"""
    try:
        return request.cookies.get("clickai_theme", "midnight") == "jarvis"
    except Exception:
        return False


def build_linked_documents_panel(db, biz_id, doc_type, doc_id, doc_data=None):
    """
    Build a 'Linked Documents' panel showing all documents related to the given doc.
    Returns clickable HTML so the user never has to search.
    
    Supported doc_types:
      - Customer-side: 'invoice', 'quote', 'delivery_note', 'credit_note', 'customer'
      - Supplier-side: 'purchase_order', 'grv', 'supplier_invoice'
    
    For 'customer', doc_id is customer_id and the panel shows totals/counts of related docs.
    For document types, the panel shows the linked customer/supplier + sibling docs in both directions.
    """
    if not biz_id or not doc_id:
        return ""
    
    try:
        # Load the source doc if not provided
        if doc_data is None:
            table_map = {
                "invoice": "invoices",
                "quote": "quotes",
                "delivery_note": "delivery_notes",
                "credit_note": "credit_notes",
                "customer": "customers",
                "purchase_order": "purchase_orders",
                "grv": "goods_received",
                "supplier_invoice": "supplier_invoices",
                "supplier": "suppliers",
            }
            tbl = table_map.get(doc_type)
            if not tbl:
                return ""
            doc_data = db.get_one(tbl, doc_id) or {}
        
        # Helpers to render link rows
        def _link_row(icon, label, url, ref, sub=""):
            sub_html = f' <span style="color:var(--text-muted);font-size:11px;">{safe_string(sub)}</span>' if sub else ""
            return f'''<a href="{url}" style="display:flex;align-items:center;gap:8px;padding:8px 10px;border-radius:6px;background:var(--bg);border:1px solid var(--border);text-decoration:none;color:var(--text);transition:all 0.15s;margin-bottom:6px;"
                onmouseover="this.style.borderColor='var(--primary)';this.style.background='rgba(139,92,246,0.05)';"
                onmouseout="this.style.borderColor='var(--border)';this.style.background='var(--bg)';">
                <span style="font-size:16px;">{icon}</span>
                <span style="font-size:12px;color:var(--text-muted);min-width:80px;">{label}</span>
                <span style="font-weight:600;color:var(--primary);">{safe_string(ref)}</span>
                {sub_html}
            </a>'''
        
        rows = []
        
        # ── Resolve invoice number this doc belongs to (used to find CNs/DNs) ──
        invoice_id = None
        invoice_number = None
        quote_id = None
        quote_number = None
        customer_id = doc_data.get("customer_id")
        customer_name = doc_data.get("customer_name", "")
        
        if doc_type == "invoice":
            invoice_id = doc_id
            invoice_number = doc_data.get("invoice_number", "")
            quote_id = doc_data.get("source_quote_id")
            quote_number = doc_data.get("source_quote_number", "")
        elif doc_type == "quote":
            quote_id = doc_id
            quote_number = doc_data.get("quote_number", "")
            invoice_id = doc_data.get("invoice_id")
            invoice_number = doc_data.get("invoice_number", "")
        elif doc_type == "delivery_note":
            invoice_id = doc_data.get("source_invoice_id")
            invoice_number = doc_data.get("source_invoice_number", "")
        elif doc_type == "credit_note":
            invoice_id = doc_data.get("invoice_id")
            invoice_number = doc_data.get("invoice_number", "")
        
        # ── For DN/CN: hop to invoice to get the source quote ──
        if doc_type in ("delivery_note", "credit_note") and invoice_id and not quote_id:
            try:
                _inv = db.get_one("invoices", invoice_id) or {}
                quote_id = _inv.get("source_quote_id")
                quote_number = _inv.get("source_quote_number", "")
                if not customer_id:
                    customer_id = _inv.get("customer_id")
                    customer_name = _inv.get("customer_name", customer_name)
            except Exception:
                pass
        
        # ── SUPPLIER-SIDE: Resolve PO/GRV/SI relationships ──
        po_id = None
        po_number = None
        grv_id = None
        grv_number = None
        si_id = None
        si_number = None
        supplier_id = doc_data.get("supplier_id") if doc_type in ("purchase_order", "grv", "supplier_invoice", "supplier") else None
        supplier_name = doc_data.get("supplier_name", "") if doc_type in ("purchase_order", "grv", "supplier_invoice") else ""
        if doc_type == "supplier":
            supplier_id = doc_id
            supplier_name = doc_data.get("name", "")
        
        if doc_type == "purchase_order":
            po_id = doc_id
            po_number = doc_data.get("po_number", "")
        elif doc_type == "grv":
            grv_id = doc_id
            grv_number = doc_data.get("grv_number", "")
            po_id = doc_data.get("po_id")
            po_number = doc_data.get("po_number", "")
        elif doc_type == "supplier_invoice":
            si_id = doc_id
            si_number = doc_data.get("invoice_number", "")
            # SI does not store po_id directly — derive from notes field "From PO: PO-xxxx"
            _notes = doc_data.get("notes", "") or ""
            try:
                import re as _re
                _po_match = _re.search(r'PO[-\s]?\d+', _notes, _re.IGNORECASE)
                if _po_match:
                    _po_num_from_notes = _po_match.group(0).upper().replace(" ", "")
                    if not _po_num_from_notes.startswith("PO-"):
                        _po_num_from_notes = "PO-" + _po_num_from_notes.replace("PO", "").lstrip("-")
                    _all_pos = db.get("purchase_orders", {"business_id": biz_id}) or []
                    _po_match_rec = next((p for p in _all_pos if (p.get("po_number") or "").upper() == _po_num_from_notes.upper()), None)
                    if _po_match_rec:
                        po_id = _po_match_rec.get("id")
                        po_number = _po_match_rec.get("po_number")
            except Exception:
                pass
        
        # ── Customer link (always show if we have one) ──
        if customer_id and doc_type != "customer":
            rows.append(_link_row("👤", "Customer", f"/customer/{customer_id}", customer_name or "View customer"))
        
        # ── Source quote (for invoice / DN / CN) ──
        if doc_type != "quote" and quote_id:
            rows.append(_link_row("📋", "Quote", f"/quote/{quote_id}", quote_number or "View quote"))
        
        # ── Source invoice (for quote / DN / CN) ──
        if doc_type != "invoice" and invoice_id:
            rows.append(_link_row("🧾", "Invoice", f"/invoice/{invoice_id}", invoice_number or "View invoice"))
        
        # ── For QUOTE: show resulting invoice if exists ──
        # (already handled above via invoice_id from quote.invoice_id)
        
        # ── For INVOICE / CN / DN: find sibling DNs from this invoice ──
        if invoice_number and doc_type != "delivery_note":
            try:
                all_dns = db.get("delivery_notes", {"business_id": biz_id}) or []
                siblings = [d for d in all_dns 
                            if (d.get("source_invoice_id") == invoice_id 
                                or d.get("source_invoice_number") == invoice_number)
                            and d.get("id") != doc_id]
                for d in siblings[:5]:
                    dn_num = d.get("dn_number") or d.get("delivery_note_number") or "DN"
                    dn_date = (d.get("date") or "")[:10]
                    rows.append(_link_row("📦", "Delivery Note", f"/delivery-note/{d.get('id')}", dn_num, dn_date))
            except Exception:
                pass
        
        # ── For INVOICE / DN / CN: find sibling CNs from this invoice ──
        if invoice_number and doc_type != "credit_note":
            try:
                all_cns = db.get("credit_notes", {"business_id": biz_id}) or []
                siblings = [c for c in all_cns 
                            if (c.get("invoice_id") == invoice_id 
                                or c.get("invoice_number") == invoice_number)
                            and c.get("id") != doc_id]
                for c in siblings[:5]:
                    cn_num = c.get("credit_note_number") or c.get("cn_number") or "CN"
                    cn_date = (c.get("date") or c.get("created_at") or "")[:10]
                    cn_total = c.get("total", 0)
                    sub = f"{cn_date} • {money(cn_total)}" if cn_total else cn_date
                    rows.append(_link_row("↩️", "Credit Note", f"/credit-note/{c.get('id')}", cn_num, sub))
            except Exception:
                pass
        
        # ── For QUOTE: also scan ALL invoices that source this quote (in case multiple) ──
        if doc_type == "quote":
            try:
                all_invs = db.get("invoices", {"business_id": biz_id}) or []
                for inv in all_invs:
                    if inv.get("source_quote_id") == doc_id and inv.get("id") != invoice_id:
                        i_num = inv.get("invoice_number", "")
                        i_date = (inv.get("date") or "")[:10]
                        rows.append(_link_row("🧾", "Invoice", f"/invoice/{inv.get('id')}", i_num, i_date))
            except Exception:
                pass
        
        # ════════════════════════════════════════════════════════════════════
        # SUPPLIER-SIDE LINKED DOCS
        # ════════════════════════════════════════════════════════════════════
        
        # ── Supplier link (always show if we have one) ──
        if supplier_id and doc_type != "supplier":
            rows.append(_link_row("🏭", "Supplier", f"/supplier/{supplier_id}", supplier_name or "View supplier"))
        
        # ── Source PO (for GRV / SI) ──
        if doc_type in ("grv", "supplier_invoice") and po_id:
            rows.append(_link_row("📋", "Purchase Order", f"/purchase/{po_id}", po_number or "View PO"))
        
        # ── For PO / SI: find sibling GRVs from this PO ──
        if po_number and doc_type != "grv":
            try:
                all_grvs = db.get("goods_received", {"business_id": biz_id}) or []
                siblings = [g for g in all_grvs 
                            if (g.get("po_id") == po_id 
                                or g.get("po_number") == po_number)
                            and g.get("id") != doc_id]
                for g in siblings[:5]:
                    g_num = g.get("grv_number") or "GRV"
                    g_date = (g.get("date") or g.get("created_at") or "")[:10]
                    rows.append(_link_row("📦", "GRV", f"/grv/{g.get('id')}", g_num, g_date))
            except Exception:
                pass
        
        # ── For PO / GRV: find sibling Supplier Invoices from this PO ──
        if po_number and doc_type != "supplier_invoice":
            try:
                all_sis = db.get("supplier_invoices", {"business_id": biz_id}) or []
                # Match by po_id (if SI ever stored it) or by notes field containing the PO number
                _po_num_upper = (po_number or "").upper()
                siblings = []
                for s in all_sis:
                    if s.get("id") == doc_id:
                        continue
                    if s.get("po_id") == po_id and po_id:
                        siblings.append(s)
                        continue
                    _s_notes = (s.get("notes", "") or "").upper()
                    if _po_num_upper and _po_num_upper in _s_notes:
                        siblings.append(s)
                for s in siblings[:5]:
                    s_num = s.get("invoice_number") or "SI"
                    s_date = (s.get("date") or "")[:10]
                    s_total = s.get("total", 0)
                    sub = f"{s_date} • {money(s_total)}" if s_total else s_date
                    rows.append(_link_row("🧾", "Supplier Invoice", f"/supplier-invoice/{s.get('id')}", s_num, sub))
            except Exception:
                pass
        
        # ── For GRV / SI: also try to find a related GRV/SI when no PO is known ──
        # (e.g. SI without PO link — find GRVs by supplier within ~14 days)
        if doc_type == "supplier_invoice" and not po_id and supplier_id:
            try:
                all_grvs = db.get("goods_received", {"business_id": biz_id}) or []
                _si_date = doc_data.get("date", "") or ""
                related_grvs = []
                for g in all_grvs:
                    if g.get("supplier_id") != supplier_id:
                        continue
                    g_date = g.get("date") or g.get("created_at") or ""
                    if _si_date and g_date:
                        try:
                            from datetime import datetime as _dt2
                            _d1 = _dt2.fromisoformat(_si_date[:10])
                            _d2 = _dt2.fromisoformat(g_date[:10])
                            if abs((_d1 - _d2).days) <= 14:
                                related_grvs.append(g)
                        except Exception:
                            pass
                for g in related_grvs[:3]:
                    g_num = g.get("grv_number") or "GRV"
                    g_date = (g.get("date") or g.get("created_at") or "")[:10]
                    rows.append(_link_row("📦", "GRV (likely)", f"/grv/{g.get('id')}", g_num, g_date))
            except Exception:
                pass
        
        if not rows:
            return ""
        
        return f'''
        <div style="background:var(--card);border:1px solid var(--border);border-radius:10px;padding:16px;margin-bottom:20px;">
            <div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;">
                <span style="font-size:13px;font-weight:600;color:var(--text);letter-spacing:0.5px;">🔗 LINKED DOCUMENTS</span>
                <span style="font-size:11px;color:var(--text-muted);">— click to navigate</span>
            </div>
            {"".join(rows)}
        </div>
        '''
    except Exception as _e:
        # Silent fail — panel is helpful but never break the page
        try:
            logger.warning(f"build_linked_documents_panel failed: {_e}")
        except Exception:
            pass
        return ""


def has_reactor_hud():
    """Check if current theme supports the reactor HUD (all dark themes)"""
    try:
        theme = request.cookies.get("clickai_theme", "midnight")
        return theme in ("jarvis", "midnight", "cyber", "emerald", "sunset", "slate", "light")
    except Exception:
        return False


def _jarvis_global_hud(title, content):
    """Wrap any page content with a mini Jarvis reactor header + Zane extension.
    Only used for pages that don't have their own custom HUD.
    """
    try:
        page_name = title.upper().replace(" - CLICK AI", "").strip()
        
        hdr = f'''
        <div class="j-hud-wrap" data-page="{page_name}">
            <div class="j-hero" style="padding:10px 20px 0;">
                <div class="j-cn"></div>
                <div class="j-rx page" onclick="jzToggle()" style="width:180px;height:180px;z-index:10;">
                    <div class="j-rg r1"></div>
                    <div class="j-rg r2"></div>
                    <div class="j-rg r3"></div>
                    <div class="j-rg r4"></div>
                    <div class="j-core" style="inset:48px;">
                        <div class="j-brand" style="font-size:14px;">CLICK.AI</div>
                        <div class="j-sub">// BUSINESS INTELLIGENCE</div>
                        <div class="j-ai">ZANE AI</div>
                    </div>
                    <div class="j-hint">CLICK TO TALK TO ZANE</div>
                </div>
                <div class="j-cn R"></div>
                <div class="j-plbl">
                    <div class="j-pn">{page_name}</div>
                </div>
            </div>
            <div class="j-hud-pad" id="jHudPad"></div>
            <div class="j-zane-ext" id="jZaneExt">
                <div class="j-scanline"></div>
                <div class="j-zane-ctx">
                    <div class="jzc-left"><span class="jzc-ci"><span class="jzd"></span>{page_name}</span><span class="jzc-ci"><span class="jzd"></span>AI READY</span></div>
                    <button class="jzc-close" onclick="jzToggle()">CLOSE [ESC]</button>
                </div>
                <div class="j-zane-layout">
                    <div class="j-zane-left"><div class="j-zane-msgs" id="jzMsgsL"></div></div>
                    <div class="j-zane-center">
                        <div class="jzc-label">ZANE AI</div>
                        <div class="jzc-status">ONLINE</div>
                        <div class="jzc-actions">
                            <button class="jzc-btn" onclick="jzSend('Give me a business summary')">Business Summary</button>
                            <button class="jzc-btn" onclick="jzSend('Who owes me the most?')">Top Debtors</button>
                            <button class="jzc-btn" onclick="jzSend('Show low stock items')">Low Stock</button>
                            <button class="jzc-btn" onclick="jzSend('Run business pulse')">Run Pulse</button>
                            <button class="jzc-btn" onclick="jzSend('Cash flow forecast')">Cash Flow</button>
                            <button class="jzc-btn" onclick="jzSend('Create new invoice')">New Invoice</button>
                        </div>
                    </div>
                    <div class="j-zane-right"><div class="j-zane-msgs" id="jzMsgsR"></div></div>
                </div>
                <div class="j-zane-inp">
                    <input type="text" placeholder="Ask Zane anything..." id="jzInput" onkeydown="if(event.key==='Enter'){{jzSend(this.value);this.value=''}}">
                    <button class="jzs" onclick="jzSend(document.getElementById('jzInput').value);document.getElementById('jzInput').value=''">SEND</button>
                </div>
            </div>
        </div>
        <script>
        function jzToggle(){{var ext=document.getElementById('jZaneExt');var pad=document.getElementById('jHudPad');ext.classList.toggle('open');if(pad)pad.style.display=ext.classList.contains('open')?'none':'';if(ext.classList.contains('open')){{setTimeout(function(){{document.getElementById('jzInput').focus();}},400);if(!document.getElementById('jzMsgsL').children.length){{document.getElementById('jzMsgsL').innerHTML='<div class="jzm-ai"><p>Hello! I\\'m <strong>Zane</strong>, your AI assistant. Ask me anything or use the quick actions.</p></div>';document.getElementById('jzMsgsR').innerHTML='<div class="jzm-ai"><p><strong>Quick insights loading...</strong></p><p>Ask a question to get started.</p></div>';}}}}}}
        async function jzSend(text){{if(!text||!text.trim())return;var msgsL=document.getElementById('jzMsgsL');var msgsR=document.getElementById('jzMsgsR');var input=document.getElementById('jzInput');msgsL.innerHTML+='<div class="jzm-user"><p>'+text+'</p></div>';msgsL.scrollTop=msgsL.scrollHeight;input.value='';msgsR.innerHTML='<div class="jzm-ai"><p style="opacity:0.6;">⟳ Processing...</p></div>';try{{var resp=await fetch("/api/ai",{{method:"POST",headers:{{"Content-Type":"application/json"}},body:JSON.stringify({{command:text,current_page:window.location.pathname}})}});var data=await resp.json();var reply=data.response||data.error||"Sorry, I had trouble with that.";var h=reply;h=h.replace(/\\*\\*(.+?)\\*\\*/g,"<strong>$1</strong>");h=h.replace(/\\*(.+?)\\*/g,"<em>$1</em>");h=h.replace(/^- (.+)$/gm,"<li>$1</li>");h=h.replace(/\\n\\n/g,"</p><p>");h=h.replace(/\\n/g,"<br>");h="<p>"+h+"</p>";msgsR.innerHTML='<div class="jzm-ai">'+h+"</div>";msgsR.scrollTop=msgsR.scrollHeight;if(data.navigate&&!data.error){{var t=data.navigate;if(t&&t.startsWith("/")&&t!==window.location.pathname){{setTimeout(function(){{window.location.href=t;}},1500);}}}}}}catch(e){{msgsR.innerHTML='<div class="jzm-ai"><p style="color:var(--danger,#ff4466);">Error. Try again.</p></div>';}}}}
        document.addEventListener('keydown',function(e){{if(e.key==='Escape'){{var ext=document.getElementById('jZaneExt');if(ext&&ext.classList.contains('open'))jzToggle();}}}});
        </script>
        '''
        
        tl = jarvis_techline()
        return JARVIS_HUD_CSS + THEME_REACTOR_SKINS + hdr + content + tl
    except Exception:
        return content


