# QUICK-ADD EXPENSE API + OFFLINE SYNC
# ═══════════════════════════════════════════════════════════════

@app.route("/api/expenses/quick-add", methods=["POST"])
@login_required
def api_expenses_quick_add():
    """Quick-add expense from form — works with offline sync too"""
    try:
        data = request.get_json() or {}
        business = Auth.get_current_business()
        biz_id = business.get("id") if business else None
        user = Auth.get_current_user()
        
        if not biz_id:
            return jsonify({"success": False, "error": "No business selected"})
        
        description = (data.get("description") or "").strip()
        total_amount = float(data.get("total") or data.get("amount") or 0)
        category = (data.get("category") or "General Expenses").strip()
        supplier = (data.get("supplier") or "").strip()
        payment_method = (data.get("payment_method") or "cash").lower()
        expense_date = data.get("date") or today()
        
        if total_amount <= 0:
            return jsonify({"success": False, "error": "Amount must be greater than 0"})
        if not description:
            return jsonify({"success": False, "error": "Description required"})
        
        # Calculate VAT (included in total)
        no_vat_cats = ["fuel", "entertainment", "meals", "membership"]
        is_no_vat = any(nv in category.lower() for nv in no_vat_cats)
        
        if is_no_vat:
            vat_amount = 0.0
            net_amount = total_amount
        else:
            vat_amount = round(total_amount * 0.15 / 1.15, 2)
            net_amount = round(total_amount - vat_amount, 2)
        
        # GL code
        expense_account = IndustryKnowledge.get_gl_code(category, business_id=biz_id)
        
        desc = f"{supplier} - {description}".strip(" -") if supplier else description
        is_offline = data.get("offline_date") is not None
        if is_offline:
            desc += " [OFFLINE]"
        
        expense = RecordFactory.expense(
            business_id=biz_id,
            description=desc,
            amount=total_amount,
            date=expense_date,
            category=category,
            category_code=expense_account,
            vat=vat_amount,
            net=net_amount,
            supplier=supplier,
            supplier_name=supplier,
            payment_method=payment_method,
            status="paid",
            created_by=user.get("id") if user else None
        )
        
        success, result = db.save("expenses", expense)
        if not success:
            return jsonify({"success": False, "error": f"Save failed: {str(result)[:100]}"})
        
        # GL entries
        vat_claimable = 0.0 if is_no_vat else vat_amount
        journal_entries = [
            {"account_code": expense_account, "debit": round(total_amount - vat_claimable, 2), "credit": 0},
        ]
        if vat_claimable > 0:
            journal_entries.append({"account_code": gl(biz_id, "vat_input"), "debit": round(vat_claimable, 2), "credit": 0})
        # Credit the correct account based on how it was paid
        credit_account = {"cash": gl(biz_id, "cash"), "petty": gl(biz_id, "petty_cash"), "eft": gl(biz_id, "bank"), "card": gl(biz_id, "bank")}.get(payment_method, gl(biz_id, "bank"))
        journal_entries.append({"account_code": credit_account, "debit": 0, "credit": round(total_amount, 2)})
        
        create_journal_entry(biz_id, expense_date, desc[:50], f"EXP-{expense['id'][:8]}", journal_entries)
        
        logger.info(f"[EXPENSE QUICK-ADD] {desc} R{total_amount:.2f} cat={category} GL={expense_account}{' (OFFLINE SYNC)' if is_offline else ''}")
        
        # === ALLOCATION LOG ===
        try:
            if log_allocation:
                log_allocation(
                    business_id=biz_id, allocation_type="manual_expense", source_table="expenses", source_id=expense["id"],
                    description=desc[:200], amount=total_amount, gl_entries=journal_entries,
                    category=category, category_code=expense_account,
                    supplier_name=supplier_display, payment_method=payment_method,
                    reference=reference_no, transaction_date=expense_date,
                    created_by=user.get("id") if user else "", created_by_name=user.get("name", "") if user else ""
                )
        except Exception:
            pass
        
        return jsonify({"success": True, "id": expense["id"], "message": f"Expense R{total_amount:,.2f} saved"})
        
    except Exception as e:
        logger.error(f"[EXPENSE QUICK-ADD] Error: {e}")
        return jsonify({"success": False, "error": str(e)[:200]})


@app.route("/api/expenses/sync-offline", methods=["POST"])
@login_required
def api_expenses_sync_offline():
    """Sync offline-queued expenses"""
    try:
        data = request.get_json() or {}
        expenses_queue = data.get("expenses", [])
        
        if not expenses_queue:
            return jsonify({"success": True, "synced": 0, "message": "Nothing to sync"})
        
        synced = 0
        errors = []
        
        for exp in expenses_queue:
            try:
                # Re-use the quick-add logic by calling internally
                business = Auth.get_current_business()
                biz_id = business.get("id") if business else None
                user = Auth.get_current_user()
                
                description = (exp.get("description") or "").strip()
                total_amount = float(exp.get("total") or exp.get("amount") or 0)
                category = (exp.get("category") or "General Expenses").strip()
                supplier = (exp.get("supplier") or "").strip()
                payment_method = (exp.get("payment_method") or "cash").lower()
                expense_date = exp.get("offline_date") or today()
                
                if total_amount <= 0 or not description:
                    errors.append(f"Invalid expense: {description}")
                    continue
                
                no_vat_cats = ["fuel", "entertainment", "meals", "membership"]
                is_no_vat = any(nv in category.lower() for nv in no_vat_cats)
                vat_amount = 0.0 if is_no_vat else round(total_amount * 0.15 / 1.15, 2)
                net_amount = round(total_amount - vat_amount, 2)
                
                expense_account = IndustryKnowledge.get_gl_code(category, business_id=biz_id)
                desc = f"{supplier} - {description}".strip(" -") if supplier else description
                desc += " [OFFLINE]"
                
                expense_rec = RecordFactory.expense(
                    business_id=biz_id, description=desc, amount=total_amount,
                    date=expense_date, category=category, category_code=expense_account,
                    vat=vat_amount, net=net_amount, supplier=supplier, supplier_name=supplier,
                    payment_method=payment_method, status="paid",
                    created_by=user.get("id") if user else None
                )
                
                success, _ = db.save("expenses", expense_rec)
                if not success:
                    errors.append(f"Failed: {desc}")
                    continue
                
                vat_claimable = 0.0 if is_no_vat else vat_amount
                je = [{"account_code": expense_account, "debit": round(total_amount - vat_claimable, 2), "credit": 0}]
                if vat_claimable > 0:
                    je.append({"account_code": gl(biz_id, "vat_input"), "debit": round(vat_claimable, 2), "credit": 0})
                je.append({"account_code": gl(biz_id, "bank"), "debit": 0, "credit": round(total_amount, 2)})
                create_journal_entry(biz_id, expense_date, desc[:50], f"EXP-{expense_rec['id'][:8]}", je)
                
                synced += 1
                logger.info(f"[EXPENSE OFFLINE SYNC] {desc} R{total_amount:.2f}")
                
            except Exception as e:
                errors.append(str(e)[:80])
        
        msg = f"Synced {synced}/{len(expenses_queue)} offline expenses"
        return jsonify({"success": True, "synced": synced, "errors": errors, "message": msg})
        
    except Exception as e:
        return jsonify({"success": False, "error": str(e)[:200]})


@app.route("/api/quotes/sync-offline", methods=["POST"])
@login_required
def api_quotes_sync_offline():
    """Sync offline-queued quotes"""
    try:
        data = request.get_json() or {}
        quotes_queue = data.get("quotes", [])
        
        if not quotes_queue:
            return jsonify({"success": True, "synced": 0, "message": "Nothing to sync"})
        
        user = Auth.get_current_user()
        business = Auth.get_current_business()
        biz_id = business.get("id") if business else None
        synced = 0
        errors = []
        
        for q in quotes_queue:
            try:
                items = q.get("items", [])
                customer_id = q.get("customer_id", "")
                customer_name = q.get("customer_name", "Walk-in")
                
                subtotal = Decimal(str(q.get("subtotal", 0)))
                vat = Decimal(str(q.get("vat", 0)))
                total = Decimal(str(q.get("total", 0)))
                
                if subtotal == 0:
                    subtotal = sum(Decimal(str(item.get("total", 0))) for item in items)
                    vat = (subtotal * VAT_RATE).quantize(Decimal("0.01"))
                    total = subtotal + vat
                
                quote_date = q.get("offline_date") or today()
                
                quote_id = generate_id()
                quote_num = f"Q{int(time.time()) % 100000:05d}"
                
                quote = {
                    "id": quote_id,
                    "business_id": biz_id,
                    "quote_number": quote_num,
                    "date": quote_date,
                    "valid_until": "",
                    "customer_id": safe_uuid(customer_id) if customer_id else None,
                    "customer_name": customer_name,
                    "items": json.dumps(items),
                    "subtotal": float(subtotal),
                    "vat": float(vat),
                    "total": float(total),
                    "status": "draft",
                    "notes": f"OFFLINE QUOTE — synced {now()}",
                    "created_by": user.get("id") if user else None,
                    "created_at": q.get("offline_time") or now()
                }
                
                success, err = db.save("quotes", quote)
                if not success:
                    errors.append(f"Quote for {customer_name}: {str(err)[:80]}")
                    continue
                
                synced += 1
                logger.info(f"[QUOTE OFFLINE SYNC] {quote_num} for {customer_name} R{total:.2f}")
                
            except Exception as e:
                errors.append(str(e)[:80])
        
        msg = f"Synced {synced}/{len(quotes_queue)} offline quotes"
        return jsonify({"success": True, "synced": synced, "errors": errors, "message": msg})
        
    except Exception as e:
        return jsonify({"success": False, "error": str(e)[:200]})


@app.route("/api/customers/sync-offline", methods=["POST"])
@login_required
def api_customers_sync_offline():
    """Sync offline-queued customers/suppliers"""
    try:
        data = request.get_json() or {}
        queue = data.get("customers", [])
        
        if not queue:
            return jsonify({"success": True, "synced": 0, "message": "Nothing to sync"})
        
        user = Auth.get_current_user()
        business = Auth.get_current_business()
        biz_id = business.get("id") if business else None
        synced = 0
        errors = []
        
        for item in queue:
            try:
                name = (item.get("name") or "").strip()
                entity_type = item.get("type", "customer")
                
                if not name:
                    continue
                
                record = {
                    "id": generate_id(),
                    "business_id": biz_id,
                    "name": name,
                    "created_at": item.get("offline_date") or now(),
                    "notes": f"Added offline — synced {now()}"
                }
                
                table = "customers" if entity_type == "customer" else "suppliers"
                success, err = db.save(table, record)
                
                if not success:
                    errors.append(f"{name}: {str(err)[:80]}")
                    continue
                
                synced += 1
                logger.info(f"[{entity_type.upper()} OFFLINE SYNC] {name}")
                
            except Exception as e:
                errors.append(str(e)[:80])
        
        msg = f"Synced {synced}/{len(queue)} offline customers/suppliers"
        return jsonify({"success": True, "synced": synced, "errors": errors, "message": msg})
        
    except Exception as e:
        return jsonify({"success": False, "error": str(e)[:200]})


# ══════════════════════════════════════════════════════════════════════════════
# DESTRUCTIVE: DELETE ALL CUSTOMERS / DELETE ALL SUPPLIERS
# Role-gated to owner/admin. Requires confirmation phrase "DELETE ALL" in body.
# Intended for clearing junk records after a failed import before re-importing
# with a working parser. Invoices and financial records are NOT touched.
# ══════════════════════════════════════════════════════════════════════════════

@app.route("/api/customers/delete-all", methods=["POST"])
@login_required
def api_customers_delete_all():
    """Delete ALL customers for the current business. Owner/admin only.
    Requires {"confirm": "DELETE ALL"} in request body."""
    try:
        user = Auth.get_current_user()
        business = Auth.get_current_business()
        biz_id = business.get("id") if business else None
        
        if not biz_id:
            return jsonify({"success": False, "error": "No business selected"}), 400
        
        role = get_user_role()
        if role not in ("owner", "admin"):
            return jsonify({"success": False, "error": "Only owners and admins can delete all customers"}), 403
        
        data = request.get_json(silent=True) or {}
        if (data.get("confirm") or "").strip() != "DELETE ALL":
            return jsonify({"success": False, "error": "Confirmation phrase not provided"}), 400
        
        customers = db.get("customers", {"business_id": biz_id}, limit=5000) or []
        if not customers:
            return jsonify({"success": True, "deleted": 0, "message": "No customers to delete"})
        
        ids = [c.get("id") for c in customers if c.get("id")]
        total_before = len(ids)
        
        success, failed = db.delete_many("customers", ids, biz_id)
        
        logger.warning(f"[DELETE-ALL] biz={biz_id} user={user.get('email') if user else '?'} "
                       f"customers deleted: {success}/{total_before} (failed={failed})")
        try:
            AuditLog.log("DELETE_ALL", "customers", biz_id,
                         details=f"Bulk delete: {success} customers removed "
                                 f"(failed={failed}) by {user.get('email') if user else 'unknown'}")
        except Exception:
            pass
        
        return jsonify({
            "success": True,
            "deleted": success,
            "failed": failed,
            "total": total_before,
            "message": f"Deleted {success} of {total_before} customers"
        })
    except Exception as e:
        logger.error(f"[DELETE-ALL customers] Error: {e}")
        return jsonify({"success": False, "error": str(e)[:200]}), 500


