@app.route("/grv/new", methods=["GET", "POST"])
@login_required
def grv_new():
    """Create new GRV (goods received) — pick or create supplier"""
    user = Auth.get_current_user()
    business = Auth.get_current_business()
    biz_id = business.get("id") if business else None
    
    if request.method == "POST":
        supplier_id = request.form.get("supplier_id", "")
        supplier_name = request.form.get("supplier_name", "").strip()
        notes = request.form.get("notes", "")
        add_stock = request.form.get("add_stock") == "1"
        
        # If new supplier, create it
        if supplier_id == "NEW" and supplier_name:
            new_sup = {"id": generate_id(), "business_id": biz_id, "name": supplier_name, "created_at": now()}
            db.save("suppliers", new_sup)
            supplier_id = new_sup["id"]
        elif supplier_id and supplier_id != "NEW":
            sup = db.get_one("suppliers", supplier_id)
            if sup and not supplier_name:
                supplier_name = sup.get("name", "")
        
        # Get items
        items = []
        descriptions = request.form.getlist("item_desc[]")
        quantities = request.form.getlist("item_qty[]")
        codes = request.form.getlist("item_code[]")
        costs = request.form.getlist("item_cost[]")
        
        for i, desc in enumerate(descriptions):
            if desc.strip():
                qty = float(quantities[i] or "1") if i < len(quantities) else 1
                code = codes[i].strip() if i < len(codes) else ""
                cost = float(costs[i] or "0") if i < len(costs) else 0
                items.append({"description": desc.strip(), "quantity": qty, "code": code, "cost_price": cost})
        
        if not items:
            flash("Add at least one item", "error")
            return redirect("/grv/new")
        
        existing = db.get("goods_received", {"business_id": biz_id}) or []
        grv_num = next_document_number("GRV-", existing, "grv_number")
        grv_id = generate_id()
        
        grv = {
            "id": grv_id, "business_id": biz_id, "grv_number": grv_num,
            "date": today(), "supplier_id": supplier_id or None, "supplier_name": supplier_name,
            "items": json.dumps(items), "notes": notes, "status": "received", "created_at": now()
        }
        success, _ = db.save("goods_received", grv)
        
        if success:
            # Book stock in if requested
            grv_gl_total = 0.0
            if add_stock:
                all_stock = db.get_all_stock(biz_id)
                for item in items:
                    code = item.get("code", "")
                    # Try match by code
                    matched = None
                    for s in all_stock:
                        if code and s.get("code", "").strip().upper() == code.upper():
                            matched = s
                            break
                    if matched:
                        current_qty = float(matched.get("qty") or matched.get("quantity") or 0)
                        new_qty = current_qty + item["quantity"]
                        cost_price = float(item.get("cost_price", 0) or 0)
                        stock_updates = {"qty": new_qty, "quantity": new_qty}
                        
                        # Update cost and recalc selling price (maintain markup %)
                        if cost_price > 0:
                            old_cost = float(matched.get("cost") or matched.get("cost_price") or 0)
                            old_sell = float(matched.get("price") or matched.get("selling_price") or 0)
                            stock_updates["cost"] = cost_price
                            stock_updates["cost_price"] = cost_price
                            if old_cost > 0 and old_sell > 0:
                                markup_ratio = old_sell / old_cost
                                new_sell = round(cost_price * markup_ratio, 2)
                            elif cost_price > 0:
                                new_sell = round(cost_price * 1.3, 2)
                            else:
                                new_sell = old_sell
                            stock_updates["selling_price"] = new_sell
                            stock_updates["price"] = new_sell
                            logger.info(f"[GRV] Price recalc {matched.get('code','')}: cost {old_cost}->{cost_price}, sell {old_sell}->{new_sell}")
                        
                        db.update_stock(matched["id"], stock_updates, biz_id)
                        try:
                            db.save("stock_movements", RecordFactory.stock_movement(
                                business_id=biz_id, stock_id=matched["id"], movement_type="in",
                                quantity=item["quantity"], reference=f"GRV {grv_num}"
                            ))
                        except: pass
                        # Accumulate GL value
                        grv_gl_total += item["quantity"] * cost_price
            
            # --- GL Journal Entry for GRV stock received ---
            if grv_gl_total > 0:
                try:
                    stock_acc = gl(biz_id, "stock")
                    cogs_acc = gl(biz_id, "cogs")
                    grv_gl_entries = [
                        {"account_code": stock_acc, "debit": grv_gl_total, "credit": 0},   # DR Stock (asset in)
                        {"account_code": cogs_acc, "debit": 0, "credit": grv_gl_total},   # CR COGS / Purchases
                    ]
                    create_journal_entry(biz_id, today(), f"GRV {grv_num} stock received from {supplier_name}", f"GRV {grv_num}", grv_gl_entries)
                    logger.info(f"[GRV] GL posted: GRV {grv_num} R{grv_gl_total:.2f} stock_acc={stock_acc} cogs_acc={cogs_acc}")
                except Exception as gl_err:
                    logger.error(f"[GRV] GL entry failed (non-critical): {gl_err}")
            
            flash(f"GRV {grv_num} created — {len(items)} items received from {supplier_name}", "success")
            return redirect(f"/grv/{grv_id}")
        
        flash("Failed to save GRV", "error")
        return redirect("/grv/new")
    
    # GET - show form
    suppliers = db.get("suppliers", {"business_id": biz_id}) if biz_id else []
    supplier_options = '<option value="">-- Select Supplier --</option>'
    supplier_options += '<option value="NEW" style="color:var(--primary);">+ New Supplier</option>'
    for s in sorted(suppliers, key=lambda x: x.get("name", "")):
        supplier_options += f'<option value="{s.get("id")}">{safe_string(s.get("name", ""))}</option>'
    
    content = f'''
    <div style="margin-bottom:15px;">
        <a href="/grv" style="color:var(--text-muted);">← Back to GRVs</a>
    </div>
    <div class="card">
        <h2 style="margin-top:0;">📦 New Goods Received Voucher</h2>
        <form method="POST">
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:15px;margin-bottom:15px;">
                <div>
                    <label>Supplier</label>
                    <select name="supplier_id" id="supSelect" onchange="if(this.value==='NEW')document.getElementById('newSupName').style.display='block'" class="form-input" style="width:100%;">
                        {supplier_options}
                    </select>
                    <input type="text" name="supplier_name" id="newSupName" placeholder="New supplier name" class="form-input" style="display:none;margin-top:6px;width:100%;">
                </div>
                <div>
                    <label>Notes</label>
                    <input type="text" name="notes" placeholder="e.g. Cash purchase, Invoice #123" class="form-input" style="width:100%;">
                </div>
            </div>
            
            <h4>Items Received</h4>
            <table class="table" id="grvItems">
                <thead><tr><th>Code</th><th>Description</th><th>Qty</th><th>Cost Price</th><th></th></tr></thead>
                <tbody>
                    <tr>
                        <td><input type="text" name="item_code[]" class="form-input" placeholder="Code" style="width:100%;"></td>
                        <td><input type="text" name="item_desc[]" class="form-input" placeholder="Description" style="width:100%;"></td>
                        <td><input type="number" name="item_qty[]" class="form-input" value="1" step="0.01" style="width:100%;"></td>
                        <td><input type="number" name="item_cost[]" class="form-input" placeholder="0.00" step="0.01" style="width:100%;"></td>
                        <td><button type="button" onclick="this.closest('tr').remove()" style="background:var(--red);color:white;border:none;padding:6px 10px;border-radius:4px;cursor:pointer;">✕</button></td>
                    </tr>
                </tbody>
            </table>
            <button type="button" onclick="addGrvRow()" class="btn btn-secondary" style="margin:10px 0;">+ Add Row</button>
            
            <div style="margin-top:15px;">
                <label style="display:flex;align-items:center;gap:8px;cursor:pointer;">
                    <input type="checkbox" name="add_stock" value="1" checked> Auto-update stock quantities (match by code)
                </label>
            </div>
            
            <div style="margin-top:15px;display:flex;gap:10px;">
                <button type="submit" class="btn btn-primary">💾 Save GRV</button>
                <a href="/grv" class="btn btn-secondary">Cancel</a>
            </div>
        </form>
    </div>
    <script>
    function addGrvRow() {{
        const tbody = document.querySelector('#grvItems tbody');
        const row = document.createElement('tr');
        row.innerHTML = `<td><input type="text" name="item_code[]" class="form-input" placeholder="Code" style="width:100%;"></td>
            <td><input type="text" name="item_desc[]" class="form-input" placeholder="Description" style="width:100%;"></td>
            <td><input type="number" name="item_qty[]" class="form-input" value="1" step="0.01" style="width:100%;"></td>
            <td><input type="number" name="item_cost[]" class="form-input" placeholder="0.00" step="0.01" style="width:100%;"></td>
            <td><button type="button" onclick="this.closest('tr').remove()" style="background:var(--red);color:white;border:none;padding:6px 10px;border-radius:4px;cursor:pointer;">✕</button></td>`;
        tbody.appendChild(row);
    }}
    </script>
    '''
    return render_page("New GRV", content, user, "purchases")


