# 
# CREDIT NOTES
# 

@app.route("/invoice/<invoice_id>/credit-note", methods=["GET", "POST"])
@login_required
def create_credit_note(invoice_id):
    """Create credit note from invoice - supports partial credits (specific lines)"""
    
    user = Auth.get_current_user()
    business = Auth.get_current_business()
    biz_id = business.get("id") if business else None
    
    invoice = db.get_one("invoices", invoice_id)
    if not invoice:
        return redirect("/invoices")
    
    # Handle items - Supabase may return as list or JSON string
    raw_items = invoice.get("items", "[]")
    if isinstance(raw_items, list):
        inv_items = raw_items
    elif isinstance(raw_items, str):
        try:
            inv_items = json.loads(raw_items)
        except:
            inv_items = []
    else:
        inv_items = []
    
    logger.info(f"[CREDIT NOTE] Invoice {invoice.get('invoice_number')}: {len(inv_items)} items loaded, type={type(raw_items).__name__}")
    
    if request.method == "POST":
        # ── FRAUD GUARD: Check if user is allowed to credit this invoice ──
        try:
            if FraudGuard:
                _role = get_user_role()
                _guard = FraudGuard.can_cancel_invoice(invoice, _role)
                if not _guard.get("allowed"):
                    logger.warning(f"[FRAUD GUARD] Credit note BLOCKED for {invoice.get('invoice_number')} - role:{_role} - {_guard.get('reason')}")
                    return redirect(f"/invoice/{invoice_id}?error=" + urllib.parse.quote(_guard.get("reason", "Not allowed")))
        except Exception as _fg_err:
            logger.error(f"[FRAUD GUARD] Check failed (allowing): {_fg_err}")
        
        reason = request.form.get("reason", "")
        credit_type = request.form.get("credit_type", "full")  # full or partial
        
        # Build credited items list
        credited_items = []
        cn_subtotal = Decimal("0")
        
        if credit_type == "partial":
            # Get selected line items
            selected_lines = request.form.getlist("credit_line[]")
            credit_qtys = request.form.getlist("credit_qty[]")
            
            for i, item in enumerate(inv_items):
                idx_str = str(i)
                if idx_str in selected_lines:
                    orig_qty = float(item.get("quantity") or item.get("qty") or 1)
                    credit_qty_str = credit_qtys[i] if i < len(credit_qtys) else str(orig_qty)
                    credit_qty = min(float(credit_qty_str or orig_qty), orig_qty)
                    price = float(item.get("price") or item.get("unit_price") or 0)
                    line_total = round(credit_qty * price, 2)
                    cn_subtotal += Decimal(str(line_total))
                    credited_items.append({
                        "description": item.get("description", ""),
                        "quantity": credit_qty,
                        "price": price,
                        "total": line_total
                    })
        else:
            # Full credit - all items
            for item in inv_items:
                qty = float(item.get("quantity") or item.get("qty") or 1)
                price = float(item.get("price") or item.get("unit_price") or 0)
                line_total = float(item.get("total") or item.get("line_total") or round(qty * price, 2))
                cn_subtotal += Decimal(str(line_total))
                credited_items.append({
                    "description": item.get("description", ""),
                    "quantity": qty,
                    "price": price,
                    "total": line_total
                })
        
        if not credited_items:
            return redirect(f"/invoice/{invoice_id}/credit-note?error=No+items+selected")
        
        cn_vat = (cn_subtotal * VAT_RATE).quantize(Decimal("0.01"))
        cn_total = cn_subtotal + cn_vat
        
        # Generate credit note number
        existing = db.get("credit_notes", {"business_id": biz_id}) if biz_id else []
        cn_num = next_document_number("CN-", existing, "credit_note_number")
        
        cn_id = generate_id()
        credit_note = {
            "id": cn_id,
            "business_id": biz_id,
            "credit_note_number": cn_num,
            "date": today(),
            "invoice_id": invoice_id,
            "invoice_number": invoice.get("invoice_number"),
            "customer_id": invoice.get("customer_id"),
            "customer_name": invoice.get("customer_name"),
            "reason": reason,
            "items": json.dumps(credited_items),
            "subtotal": float(cn_subtotal),
            "vat": float(cn_vat),
            "total": float(cn_total),
            "credit_type": credit_type,
            "created_by": user.get("id") if user else None,
            "created_at": now()
        }
        
        db.save("credit_notes", credit_note)
        
        # Journal entries to reverse
        create_journal_entry(
            biz_id,
            today(),
            f"Credit Note {cn_num} - {'partial ' if credit_type == 'partial' else ''}reversing {invoice.get('invoice_number', '')} - {invoice.get('customer_name', '')}",
            cn_num,
            [
                {"account_code": gl(biz_id, "sales"), "debit": float(cn_subtotal), "credit": 0},
                {"account_code": gl(biz_id, "vat_output"), "debit": float(cn_vat), "credit": 0},
                {"account_code": gl(biz_id, "debtors"), "debit": 0, "credit": float(cn_total)},
            ]
        )
        
        # Customer balance is now calculated dynamically — no manual update needed
        
        # Mark invoice as credited only if FULL credit
        if credit_type == "full":
            db.update("invoices", invoice_id, {"status": "credited"})
        else:
            db.update("invoices", invoice_id, {"status": "partial_credit"})
        
        # ── FRAUD GUARD: Log this credit note action ──
        try:
            if FraudGuard:
                FraudGuard.log_sensitive_action(
                    db, "INVOICE_CREDIT", invoice, user, biz_id,
                    reason=reason or "No reason",
                    details=f"CN {cn_num} for R{float(cn_total):.2f} ({credit_type})"
                )
        except Exception:
            pass
        
        # === ALLOCATION LOG ===
        try:
            if log_allocation:
                log_allocation(
                    business_id=biz_id, allocation_type="credit_note", source_table="credit_notes", source_id=cn_id,
                    description=f"Credit Note {cn_num} - {credit_type} - reversing {invoice.get('invoice_number', '')} - {invoice.get('customer_name', '')}",
                    amount=float(cn_total),
                    gl_entries=[
                        {"account_code": gl(biz_id, "sales"), "debit": float(cn_subtotal), "credit": 0},
                        {"account_code": gl(biz_id, "vat_output"), "debit": float(cn_vat), "credit": 0},
                        {"account_code": gl(biz_id, "debtors"), "debit": 0, "credit": float(cn_total)},
                    ],
                    customer_name=invoice.get("customer_name", ""), reference=cn_num,
                    transaction_date=today(),
                    created_by=user.get("id") if user else "", created_by_name=user.get("name", "") if user else "",
                    extra={"reason": reason, "credit_type": credit_type, "original_invoice": invoice.get("invoice_number", "")}
                )
        except Exception:
            pass
        
        return redirect(f"/credit-note/{cn_id}")
    
    # GET - build form with line item selection
    
    # ── FRAUD GUARD: Check permission before showing form ──
    _fg_warning = ""
    try:
        if FraudGuard:
            _role = get_user_role()
            _guard = FraudGuard.can_cancel_invoice(invoice, _role)
            if not _guard.get("allowed"):
                return redirect(f"/invoice/{invoice_id}?error=" + urllib.parse.quote(_guard.get("reason", "Not allowed")))
            if _guard.get("notify_owner"):
                _fg_warning = '<div style="background:rgba(245,158,11,0.15);border:1px solid rgba(245,158,11,0.3);padding:12px 16px;border-radius:8px;margin-bottom:15px;color:var(--text);"><strong>⚠ Note:</strong> The business owner will be notified about this credit note.</div>'
    except Exception:
        pass
    items_rows_html = ""
    inv_subtotal = Decimal("0")
    for i, item in enumerate(inv_items):
        qty = float(item.get("quantity") or item.get("qty") or 1)
        price = float(item.get("price") or item.get("unit_price") or 0)
        line_total = float(item.get("total") or item.get("line_total") or round(qty * price, 2))
        inv_subtotal += Decimal(str(line_total))
        items_rows_html += f'''
        <tr class="cn-line" data-idx="{i}" data-total="{line_total}">
            <td style="text-align:center;">
                <input type="checkbox" name="credit_line[]" value="{i}" class="cn-check" onchange="updateCNTotal()" checked>
            </td>
            <td>{safe_string(item.get("description", "-"))}</td>
            <td style="text-align:center;">
                <input type="number" name="credit_qty[]" value="{qty}" min="0.01" max="{qty}" step="0.01" class="cn-qty" onchange="updateCNTotal()" style="width:70px;padding:4px;border:1px solid var(--border);border-radius:4px;background:var(--bg);color:var(--text);text-align:center;">
                <span style="color:var(--text-muted);font-size:11px;">/ {qty}</span>
            </td>
            <td style="text-align:right;">{money(price)}</td>
            <td style="text-align:right;" class="cn-line-total">{money(line_total)}</td>
        </tr>
        '''
    
    error_msg = request.args.get("error", "")
    error_html = f'<div style="background:var(--red);color:white;padding:10px;border-radius:8px;margin-bottom:15px;">{error_msg}</div>' if error_msg else ""
    
    content = f'''
    {error_html}
    {_fg_warning}
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:20px;">
        <a href="/invoice/{invoice_id}" style="color:var(--text-muted);">← Back to Invoice</a>
    </div>
    
    <div class="card">
        <h2 style="margin-bottom:20px;">Create Credit Note</h2>
        
        <div style="background:rgba(239,68,68,0.1);padding:15px;border-radius:8px;margin-bottom:20px;">
            <p style="margin:0;"><strong>Invoice:</strong> {invoice.get("invoice_number")}</p>
            <p style="margin:5px 0 0 0;"><strong>Customer:</strong> {safe_string(invoice.get("customer_name", "-"))}</p>
            <p style="margin:5px 0 0 0;"><strong>Invoice Total:</strong> {money(invoice.get("total", 0))}</p>
        </div>
        
        <form method="POST">
            <!-- Credit Type Toggle -->
            <div style="margin-bottom:20px;">
                <label style="display:block;margin-bottom:8px;font-weight:bold;">Credit Type</label>
                <div style="display:flex;gap:10px;">
                    <label style="display:flex;align-items:center;gap:6px;padding:10px 20px;border:2px solid var(--primary);border-radius:8px;cursor:pointer;background:rgba(99,102,241,0.1);" id="fullLabel">
                        <input type="radio" name="credit_type" value="full" checked onchange="toggleCreditType()"> Full Credit
                    </label>
                    <label style="display:flex;align-items:center;gap:6px;padding:10px 20px;border:2px solid var(--border);border-radius:8px;cursor:pointer;" id="partialLabel">
                        <input type="radio" name="credit_type" value="partial" onchange="toggleCreditType()"> Partial Credit (select lines)
                    </label>
                </div>
            </div>
            
            <!-- Line Items Selection (shown for partial) -->
            <div id="lineSelection" style="display:none;margin-bottom:20px;">
                <label style="display:block;margin-bottom:8px;font-weight:bold;">Select Items to Credit</label>
                <table class="table" style="font-size:14px;">
                    <thead>
                        <tr style="background:var(--bg);">
                            <th style="width:40px;text-align:center;">
                                <input type="checkbox" checked onchange="toggleAllLines(this)">
                            </th>
                            <th>Description</th>
                            <th style="width:130px;text-align:center;">Credit Qty</th>
                            <th style="width:100px;text-align:right;">Price</th>
                            <th style="width:100px;text-align:right;">Total</th>
                        </tr>
                    </thead>
                    <tbody>
                        {items_rows_html}
                    </tbody>
                </table>
            </div>
            
            <!-- Credit Total Display -->
            <div style="text-align:right;margin-bottom:20px;padding:15px;background:rgba(239,68,68,0.05);border-radius:8px;border:1px solid rgba(239,68,68,0.2);">
                <div style="margin-bottom:5px;">Subtotal: <strong id="cnSubtotal">{money(inv_subtotal)}</strong></div>
                <div style="margin-bottom:5px;">VAT (15%): <strong id="cnVat">{money(float(inv_subtotal) * 0.15)}</strong></div>
                <div style="font-size:20px;color:var(--red);">Credit Amount: <strong id="cnTotal">{money(float(inv_subtotal) * 1.15)}</strong></div>
            </div>
            
            <div style="margin-bottom:20px;">
                <label style="display:block;margin-bottom:5px;font-weight:bold;">Reason for Credit Note</label>
                <textarea name="reason" class="form-input" rows="3" placeholder="e.g., Goods returned, Pricing error, Partial return..." required></textarea>
            </div>
            
            <div style="display:flex;gap:10px;">
                <button type="submit" class="btn btn-primary">Create Credit Note</button>
                <a href="/invoice/{invoice_id}" class="btn btn-secondary">Cancel</a>
            </div>
        </form>
    </div>
    
    <script>
    function toggleCreditType() {{
        const isPartial = document.querySelector('input[name="credit_type"][value="partial"]').checked;
        document.getElementById('lineSelection').style.display = isPartial ? 'block' : 'none';
        document.getElementById('fullLabel').style.borderColor = isPartial ? 'var(--border)' : 'var(--primary)';
        document.getElementById('fullLabel').style.background = isPartial ? 'transparent' : 'rgba(99,102,241,0.1)';
        document.getElementById('partialLabel').style.borderColor = isPartial ? 'var(--primary)' : 'var(--border)';
        document.getElementById('partialLabel').style.background = isPartial ? 'rgba(99,102,241,0.1)' : 'transparent';
        updateCNTotal();
    }}
    
    function toggleAllLines(master) {{
        document.querySelectorAll('.cn-check').forEach(cb => {{ cb.checked = master.checked; }});
        updateCNTotal();
    }}
    
    function updateCNTotal() {{
        const isPartial = document.querySelector('input[name="credit_type"][value="partial"]').checked;
        let subtotal = 0;
        
        if (isPartial) {{
            document.querySelectorAll('.cn-line').forEach(row => {{
                const cb = row.querySelector('.cn-check');
                const qtyInput = row.querySelector('.cn-qty');
                const price = parseFloat(row.querySelector('td:nth-child(4)').textContent.replace('R', '').replace(/,/g, '')) || 0;
                const lineTotalCell = row.querySelector('.cn-line-total');
                
                if (cb.checked) {{
                    const qty = parseFloat(qtyInput.value) || 0;
                    const lineTotal = qty * price;
                    lineTotalCell.textContent = 'R' + lineTotal.toFixed(2);
                    subtotal += lineTotal;
                    qtyInput.disabled = false;
                }} else {{
                    lineTotalCell.textContent = '-';
                    qtyInput.disabled = true;
                }}
            }});
        }} else {{
            subtotal = {float(inv_subtotal)};
        }}
        
        const vat = subtotal * 0.15;
        const total = subtotal + vat;
        document.getElementById('cnSubtotal').textContent = 'R' + subtotal.toFixed(2);
        document.getElementById('cnVat').textContent = 'R' + vat.toFixed(2);
        document.getElementById('cnTotal').textContent = 'R' + total.toFixed(2);
    }}
    </script>
    '''
    
    return render_page("Create Credit Note", content, user, "invoices")


@app.route("/credit-note/<cn_id>")
@login_required
def view_credit_note(cn_id):
    """View credit note"""
    
    user = Auth.get_current_user()
    business = Auth.get_current_business()
    
    cn = db.get_one("credit_notes", cn_id)
    if not cn:
        return redirect("/invoices")
    
    # Build clickable link to original invoice
    _cn_inv_num = cn.get("invoice_number", "-")
    _cn_inv_id = cn.get("invoice_id", "")
    if _cn_inv_id:
        _cn_inv_display = f'<a href="/invoice/{_cn_inv_id}" style="color:var(--primary);text-decoration:none;">{safe_string(_cn_inv_num)}</a>'
    elif _cn_inv_num and _cn_inv_num != "-":
        # Fallback: lookup by invoice number
        _cn_biz_id = business.get("id") if business else None
        _cn_all_inv = db.get("invoices", {"business_id": _cn_biz_id}) if _cn_biz_id else []
        _cn_inv_match = next((i for i in _cn_all_inv if i.get("invoice_number", "").upper() == _cn_inv_num.upper()), None)
        _cn_inv_display = f'<a href="/invoice/{_cn_inv_match["id"]}" style="color:var(--primary);text-decoration:none;">{safe_string(_cn_inv_num)}</a>' if _cn_inv_match else safe_string(_cn_inv_num)
    else:
        _cn_inv_display = "-"
    
    try:
        items = json.loads(cn.get("items", "[]"))
    except:
        items = []
    
    items_html = ""
    for item in items:
        price = float(item.get("price") or item.get("unit_price") or 0)
        total_excl = float(item.get("total") or item.get("line_total") or 0)
        qty = item.get("qty") or item.get("quantity") or 1
        if total_excl == 0 and price > 0:
            total_excl = round(float(qty) * price, 2)
        vat_amount = round(total_excl * 0.15, 2)
        total_incl = round(total_excl + vat_amount, 2)
        items_html += f'''
        <tr style="border-bottom:1px solid #e5e7eb;">
            <td style="padding:4px 6px;font-size:11px;">{safe_string(item.get("description", "-"))}</td>
            <td style="text-align:center;padding:4px 6px;font-size:11px;">{qty}</td>
            <td style="text-align:right;padding:4px 6px;font-size:11px;">{money(price)}</td>
            <td style="text-align:right;padding:4px 6px;font-size:11px;">{money(total_excl)}</td>
            <td style="text-align:right;padding:4px 6px;font-size:11px;font-weight:600;">{money(total_incl)}</td>
        </tr>
        '''
    
    biz_name = business.get("name", "Business") if business else "Business"
    biz_address = safe_string(business.get("address", "")).replace("\n", "<br>") if business else ""
    
    # Get customer email for email modal
    cn_cust_email = ""
    if cn.get("customer_id"):
        cn_customer = db.get_one("customers", cn.get("customer_id"))
        if cn_customer:
            cn_cust_email = cn_customer.get("email", "")
    
    # Build "Linked Documents" panel — gives one-click access to invoice/quote/customer/etc.
    cn_biz_id = business.get("id") if business else None
    linked_docs_html = ""
    try:
        linked_docs_html = build_linked_documents_panel(db, cn_biz_id, "credit_note", cn_id, cn)
        if linked_docs_html:
            linked_docs_html = '<div class="no-print">' + linked_docs_html + '</div>'
    except Exception:
        linked_docs_html = ""
    
    content = f'''
    <div class="no-print" style="display:flex;justify-content:space-between;align-items:center;margin-bottom:20px;">
        <a href="/invoices" style="color:var(--text-muted);">← Back to Invoices</a>
        <div style="display:flex;gap:10px;">
            <button class="btn btn-secondary" onclick="window.print();">🖨️ Print</button>
            <button class="btn btn-secondary" onclick="document.getElementById('cnEmailModal').style.display='flex';" style="background:rgba(153,27,27,0.15);color:#991b1b;border-color:#991b1b;">📧 Email</button>
        </div>
    </div>
    
    {linked_docs_html}
    
    <!-- CN EMAIL MODAL -->
    <div id="cnEmailModal" style="display:none;position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.7);z-index:9999;align-items:center;justify-content:center;">
        <div style="background:var(--card);padding:30px;border-radius:12px;width:90%;max-width:450px;">
            <h3 style="margin-top:0;">Email Credit Note</h3>
            <p style="color:var(--text-muted);margin-bottom:20px;">Send credit note <strong>{cn.get("credit_note_number", "")}</strong> to:</p>
            
            <input type="email" id="cnEmailTo" value="{cn_cust_email}" placeholder="customer@email.com" 
                   style="width:100%;padding:12px;border-radius:8px;border:1px solid var(--border);background:var(--bg);color:var(--text);font-size:16px;margin-bottom:15px;">
            
            <div style="display:flex;gap:10px;justify-content:flex-end;">
                <button onclick="document.getElementById('cnEmailModal').style.display='none'" class="btn btn-secondary">Cancel</button>
                <button onclick="sendCNEmail()" class="btn btn-primary" style="background:#991b1b;">Send Email</button>
            </div>
        </div>
    </div>
    
    <script>
    async function sendCNEmail() {{
        const email = document.getElementById('cnEmailTo').value.trim();
        if (!email || !email.includes('@')) {{ alert('Enter a valid email'); return; }}
        const btn = event.target;
        btn.disabled = true; btn.textContent = 'Sending...';
        try {{
            const resp = await fetch('/api/credit-note/{cn_id}/email', {{
                method: 'POST',
                headers: {{'Content-Type': 'application/json'}},
                body: JSON.stringify({{to_email: email}})
            }});
            const data = await resp.json();
            if (data.success) {{
                document.getElementById('cnEmailModal').style.display='none';
                alert('Credit note emailed successfully!');
            }} else {{
                alert(data.error || 'Failed to send');
            }}
        }} catch(e) {{ alert('Error: ' + e.message); }}
        btn.disabled = false; btn.textContent = 'Send Email';
    }}
    </script>
    
    <div class="card" style="background:white;color:#333;padding:0;overflow:hidden;">
        <!-- TOP BAR -->
        <div style="background:#991b1b;color:white;padding:25px 40px;display:flex;justify-content:space-between;align-items:center;">
            <div>
                <h1 style="margin:0;font-size:28px;font-weight:700;">{biz_name}</h1>
                {f'<p style="margin:4px 0 0 0;font-size:13px;opacity:0.8;">{biz_address}</p>' if biz_address else ''}
            </div>
            <div style="text-align:right;">
                <h2 style="margin:0;font-size:32px;font-weight:700;letter-spacing:2px;">CREDIT NOTE</h2>
            </div>
        </div>
        
        <!-- DETAILS GRID -->
        <div style="padding:10px 25px;display:grid;grid-template-columns:1fr 1fr;gap:0;border-bottom:1px solid #e5e7eb;">
            <div style="border-right:1px solid #e5e7eb;padding-right:25px;">
                <table style="width:100%;font-size:14px;color:#333;">
                    <tr><td style="padding:4px 0;color:#888;width:130px;">CN Number:</td><td style="padding:4px 0;font-weight:600;">{cn.get("credit_note_number", "-")}</td></tr>
                    <tr><td style="padding:4px 0;color:#888;">Date:</td><td style="padding:4px 0;">{cn.get("date", "-")}</td></tr>
                    <tr><td style="padding:4px 0;color:#888;">Orig. Invoice:</td><td style="padding:4px 0;">{_cn_inv_display}</td></tr>
                </table>
            </div>
            <div style="padding-left:25px;">
                <div style="font-size:11px;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:8px;font-weight:600;">Credit To</div>
                <div style="font-size:16px;font-weight:700;color:#991b1b;margin-bottom:4px;">{safe_string(cn.get("customer_name", "-"))}</div>
            </div>
        </div>
        
        <!-- REASON -->
        <div style="padding:15px 40px;background:#fef2f2;border-bottom:1px solid #fecaca;">
            <span style="font-size:13px;color:#991b1b;font-weight:600;">Reason:</span>
            <span style="font-size:13px;color:#333;"> {safe_string(cn.get("reason", "-"))}</span>
        </div>
        
        <!-- ITEMS TABLE -->
        <div style="padding:0 25px;">
            <table style="width:100%;border-collapse:collapse;font-size:14px;">
                <thead>
                    <tr style="background:#f1f5f9;border-bottom:2px solid #cbd5e1;">
                        <th style="padding:5px 6px;text-align:left;color:#475569;font-weight:600;font-size:10px;text-transform:uppercase;">Description</th>
                        <th style="padding:5px 6px;text-align:center;color:#475569;font-weight:600;font-size:10px;text-transform:uppercase;width:60px;">Qty</th>
                        <th style="padding:5px 6px;text-align:right;color:#475569;font-weight:600;font-size:10px;text-transform:uppercase;width:100px;">Excl. Price</th>
                        <th style="padding:5px 6px;text-align:right;color:#475569;font-weight:600;font-size:10px;text-transform:uppercase;width:100px;">Excl. Total</th>
                        <th style="padding:5px 6px;text-align:right;color:#475569;font-weight:600;font-size:10px;text-transform:uppercase;width:100px;">Incl. Total</th>
                    </tr>
                </thead>
                <tbody style="color:#333;">
                    {items_html}
                </tbody>
            </table>
        </div>
        
        <!-- TOTALS -->
        <div style="padding:10px 25px 15px;display:flex;justify-content:flex-end;">
            <table style="width:220px;border-collapse:collapse;">
                <tr style="border-bottom:1px solid #e5e7eb;">
                    <td style="padding:4px 8px;color:#666;font-size:11px;">Total Exclusive</td>
                    <td style="padding:4px 8px;text-align:right;color:#333;font-size:11px;">{money(cn.get("subtotal", 0))}</td>
                </tr>
                <tr style="border-bottom:1px solid #e5e7eb;">
                    <td style="padding:4px 8px;color:#666;font-size:11px;">Total VAT</td>
                    <td style="padding:4px 8px;text-align:right;color:#333;font-size:11px;">{money(cn.get("vat", 0))}</td>
                </tr>
                <tr style="background:#991b1b;">
                    <td style="padding:8px 8px;color:white;font-size:13px;font-weight:700;">CREDIT TOTAL</td>
                    <td style="padding:8px 8px;text-align:right;color:white;font-size:13px;font-weight:700;">{money(cn.get("total", 0))}</td>
                </tr>
            </table>
        </div>
    </div>
    '''
    
    return render_page(f"Credit Note {cn.get('credit_note_number', '')}", content, user, "invoices")


@app.route("/api/credit-note/<cn_id>/email", methods=["POST"])
@login_required
def api_credit_note_email(cn_id):
    """Send credit note via email"""
    try:
        data = request.get_json()
        to_email = data.get("to_email", "").strip()
        
        if not to_email or "@" not in to_email:
            return jsonify({"success": False, "error": "Valid email address required"})
        
        business = Auth.get_current_business()
        biz_id = business.get("id") if business else None
        
        cn = db.get_one("credit_notes", cn_id)
        if not cn:
            return jsonify({"success": False, "error": "Credit note not found"})
        
        biz_name = business.get("name", "Business") if business else "Business"
        cn_no = cn.get("credit_note_number", "")
        total = float(cn.get("total", 0))
        date = cn.get("date", today())
        cust_name = cn.get("customer_name", "Customer")
        reason = cn.get("reason", "-")
        
        # Parse items
        raw_items = cn.get("items", [])
        if isinstance(raw_items, str):
            try:
                items = json.loads(raw_items)
            except:
                items = []
        else:
            items = raw_items if raw_items else []
        
        items_html = ""
        for item in items:
            qty = item.get("qty") or item.get("quantity") or 1
            desc = item.get("description") or item.get("desc") or "-"
            price = float(item.get("price", 0))
            item_total = float(item.get("total", 0))
            items_html += f'<tr><td style="padding:8px;border-bottom:1px solid #eee;">{safe_string(desc)}</td><td style="padding:8px;border-bottom:1px solid #eee;text-align:center;">{qty}</td><td style="padding:8px;border-bottom:1px solid #eee;text-align:right;">R{price:,.2f}</td><td style="padding:8px;border-bottom:1px solid #eee;text-align:right;">R{item_total:,.2f}</td></tr>'
        
        subtotal = float(cn.get("subtotal", 0))
        vat = float(cn.get("vat", 0))
        
        subject = f"Credit Note {cn_no} from {biz_name}"
        
        biz_phone = business.get("phone", "") if business else ""
        biz_email_addr = business.get("email", "") if business else ""
        biz_address = safe_string(business.get("address", "")).replace("\n", "<br>") if business else ""
        orig_inv = cn.get("invoice_number", "-")
        
        body_html = f'''<html><body style="font-family:Arial,sans-serif;font-size:13px;color:#333;">
        <p>Dear {cust_name},</p>
        <p>Please find attached Credit Note <strong>{cn_no}</strong> for <strong>R{total:,.2f}</strong>.</p>
        <p>This credit has been applied to your account.</p>
        <hr style="border:none;border-top:1px solid #ddd;margin:15px 0 8px;">
        <p style="color:#999;font-size:10px;">{biz_name} | {biz_phone} | {biz_email_addr}<br>Sent via Click AI</p>
        </body></html>'''
        
        body_text = f"Credit Note {cn_no} from {biz_name}\n\nDear {cust_name},\n\nPlease find attached Credit Note {cn_no} for R{total:,.2f}.\n\nThis credit has been applied to your account.\n\n{biz_name}"
        
        att_items = ""
        for item in items:
            qty = item.get("qty") or item.get("quantity") or 1
            desc = safe_string(item.get("description") or item.get("desc") or "-")
            price = float(item.get("price", 0))
            item_total = float(item.get("total", 0)) or round(float(qty) * price, 2)
            att_items += f'<tr style="border-bottom:1px solid #e5e7eb;"><td style="padding:5px 8px;font-size:11px;">{desc}</td><td style="text-align:center;padding:5px 8px;font-size:11px;">{qty}</td><td style="text-align:right;padding:5px 8px;font-size:11px;">R{price:,.2f}</td><td style="text-align:right;padding:5px 8px;font-size:11px;">R{item_total:,.2f}</td></tr>'
        
        attachment_html = f'''<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Credit Note {cn_no}</title>
        <style>body{{font-family:Arial,sans-serif;margin:0;padding:0;color:#333;font-size:12px;}}table{{width:100%;border-collapse:collapse;}}@media print{{@page{{margin:10mm 12mm;}}}}</style>
        </head><body>
        <div style="background:#991b1b;color:white;padding:12px 25px;display:flex;justify-content:space-between;align-items:center;">
            <div><div style="font-size:16px;font-weight:700;">{biz_name}</div>{f'<div style="font-size:10px;opacity:0.8;">{biz_address}</div>' if biz_address else ''}</div>
            <div style="text-align:right;"><div style="font-size:20px;font-weight:700;letter-spacing:2px;">CREDIT NOTE</div></div>
        </div>
        <div style="padding:10px 25px;display:flex;gap:40px;border-bottom:1px solid #e5e7eb;">
            <div style="flex:1;">
                <table style="font-size:11px;width:auto;"><tr><td style="padding:3px 0;color:#888;width:110px;">Credit Note #:</td><td style="font-weight:600;">{cn_no}</td></tr><tr><td style="padding:3px 0;color:#888;">Date:</td><td>{date}</td></tr><tr><td style="padding:3px 0;color:#888;">Original Invoice:</td><td>{orig_inv}</td></tr><tr><td style="padding:3px 0;color:#888;">Reason:</td><td>{safe_string(reason)}</td></tr></table>
                {f'<div style="margin-top:6px;font-size:10px;color:#666;">Tel: {biz_phone}</div>' if biz_phone else ''}
            </div>
            <div style="flex:1;">
                <div style="font-size:10px;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:4px;font-weight:600;">Credit To</div>
                <div style="font-size:13px;font-weight:700;">{safe_string(cust_name)}</div>
            </div>
        </div>
        <div style="padding:0 25px;"><table>
            <thead><tr style="background:#f1f5f9;border-bottom:2px solid #cbd5e1;">
                <th style="padding:5px 8px;text-align:left;color:#475569;font-size:10px;text-transform:uppercase;">Description</th>
                <th style="padding:5px 8px;text-align:center;color:#475569;font-size:10px;text-transform:uppercase;width:50px;">Qty</th>
                <th style="padding:5px 8px;text-align:right;color:#475569;font-size:10px;text-transform:uppercase;">Price</th>
                <th style="padding:5px 8px;text-align:right;color:#475569;font-size:10px;text-transform:uppercase;">Total</th>
            </tr></thead><tbody>{att_items}</tbody>
        </table></div>
        <div style="padding:15px 25px;text-align:right;">
            <table style="width:200px;margin-left:auto;"><tr style="border-bottom:1px solid #e5e7eb;"><td style="padding:4px 8px;color:#666;font-size:11px;">Subtotal</td><td style="padding:4px 8px;text-align:right;font-size:11px;">R{subtotal:,.2f}</td></tr><tr style="border-bottom:1px solid #e5e7eb;"><td style="padding:4px 8px;color:#666;font-size:11px;">VAT (15%)</td><td style="padding:4px 8px;text-align:right;font-size:11px;">R{vat:,.2f}</td></tr><tr style="background:#991b1b;"><td style="padding:8px;color:white;font-size:13px;font-weight:700;">CREDIT</td><td style="padding:8px;text-align:right;color:white;font-size:13px;font-weight:700;">R{total:,.2f}</td></tr></table>
        </div>
        <div style="padding:10px 25px;font-size:11px;color:#666;">This credit has been applied to your account.</div>
        </body></html>'''
        
        cn_attachment = {
            'filename': f'{cn_no}.html',
            'content': attachment_html,
            'content_type': 'text/html'
        }
        
        success = Email.send(to_email, subject, body_html, body_text, business=business, attachments=[cn_attachment])
        
        if success:
            return jsonify({"success": True, "message": f"Credit note emailed to {to_email}"})
        else:
            return jsonify({"success": False, "error": "Failed to send email. Check SMTP settings."})
    except Exception as e:
        logger.error(f"[CN EMAIL ERROR] {e}")
        return jsonify({"success": False, "error": str(e)})


